  ('courses', 'course-faithonomics-core', '{"id":"course-faithonomics-core","slug":"faithonomics-economic-discipleship","title":"Faithonomics Economic Discipleship","summary":"Eight levels that align work, stewardship, ownership, integrity and economic impact with God''s framework.","description":"A structured Faithonomics LMS pathway with 8 levels, 32 sessions, step-based teaching blocks, interactive activities, written reflections and completion tracking.","imageUrl":"/Faithonomics/faithonomics-logo.png","status":"published","pricePlanIds":["plan-faithonomics-core"],"storeProductIds":["product-faithonomics-core"],"isFree":false,"lecturerIds":["member-lecturer-001"],"estimatedHours":32,"certificateTemplateId":"certificate-faithonomics-core","theme":{"primary":"#234638","accent":"#B99245"}}'::jsonb, null, null, null, null, null, null, null, null, null, 'published', null),
  ('modules', 'level-1', '{"id":"level-1","courseId":"course-faithonomics-core","title":"Level 1: Economic Alignment","description":"Move from economic pressure to intentional alignment.","sequence":1,"imageUrl":"https://static.wixstatic.com/media/7638b6_c719b145dedf4638a21fa62bb71046bc~mv2.png","imageAlt":"Papercraft classroom scene with a laptop, checklist, cross-lit city and open path."}'::jsonb, 'course-faithonomics-core', null, null, null, null, null, null, null, null, null, 1),
  ('modules', 'level-2', '{"id":"level-2","courseId":"course-faithonomics-core","title":"Level 2: God''s Economic Framework","description":"Understand creation, household, and community as economic foundations.","sequence":2}'::jsonb, 'course-faithonomics-core', null, null, null, null, null, null, null, null, null, 2),
  ('modules', 'level-3', '{"id":"level-3","courseId":"course-faithonomics-core","title":"Level 3: Economic Renewal","description":"Explore identity, repentance, and the power to change economic habits.","sequence":3}'::jsonb, 'course-faithonomics-core', null, null, null, null, null, null, null, null, null, 3),
