  ('modules', 'level-5', '{"id":"level-5","courseId":"course-faithonomics-core","title":"Level 5: God the Economist","description":"Practise abundance, ownership, and creative stewardship.","sequence":5}'::jsonb, 'course-faithonomics-core', null, null, null, null, null, null, null, null, null, 5),
  ('modules', 'level-6', '{"id":"level-6","courseId":"course-faithonomics-core","title":"Level 6: The Great Command","description":"Let love set the standard for enterprise, access, and business culture.","sequence":6}'::jsonb, 'course-faithonomics-core', null, null, null, null, null, null, null, null, null, 6),
  ('modules', 'level-7', '{"id":"level-7","courseId":"course-faithonomics-core","title":"Level 7: Godly Economic Practices","description":"Develop practical habits for work, generosity, and management.","sequence":7}'::jsonb, 'course-faithonomics-core', null, null, null, null, null, null, null, null, null, 7),
  ('modules', 'level-8', '{"id":"level-8","courseId":"course-faithonomics-core","title":"Level 8: Economic Integrity","description":"Confront idolatry, hidden costs, and the discipline of enough.","sequence":8}'::jsonb, 'course-faithonomics-core', null, null, null, null, null, null, null, null, null, 8),
  ('lessons', 'level-1-session-1-the-daily-grind', '{"id":"level-1-session-1-the-daily-grind","courseId":"course-faithonomics-core","moduleId":"level-1","title":"Session 1: The Daily Grind","summary":"To explore the core Faithonomics principle of \"The Daily Grind\": economics is the study of everyday choices, and those choices must be shaped by our faith, biblical wisdom, and Christ-like moral convictions.","sequence":1,"required":true,"estimatedMinutes":145,"imageUrl":"https://static.wixstatic.com/media/7638b6_58ab5c742514421194d57f0decba0044~mv2.png","imageAlt":"Papercraft Faithonomics choices scene for the opening session.","content":[{"id":"level-1-session-1-the-daily-grind-session-teaching-video","kind":"video","title":"Step 1: Choices","body":"Watch the teaching video. At 3:26 it pauses for a checkpoint quiz, then unlocks the next step only after the quiz is completed and the video reaches the end.","url":"https://youtu.be/_0sm9yWHgG4","videoCheckpoint":{"id":"daily-grind-video-checkpoint","timeSeconds":206,"durationSeconds":321,"title":"Interactive Quiz: The Daily Grind","questions":[{"id":"daily-grind-thabo-choice","prompt":"Thabo has R50. The latte costs R45. The coffee and muffin costs R49. Why might Thabo still choose the R49 option?","choices":["Because spending almost everything is always wise","Because the muffin may help him get through the morning","Because the latte is a bad product","Because the coffee shop owner told him to choose it","Because cheaper choices are always selfish","Because the muffin makes the coffee free"],"correctAnswer":"Because the muffin may help him get through the morning","feedback":"Correct. Thabo is not only asking, \"What is cheaper?\" He is asking, \"What will help me use what I have well today?\" This shows that everyday choices are shaped by needs, values, and the situation."},{"id":"daily-grind-thabo-decision","prompt":"Which question best describes what is happening inside Thabo''s decision?","choices":["How can I buy the most expensive thing?","How can I copy what other people are buying?","How can I use my limited money in a way that serves my day well?","How can I avoid thinking about my choice?","How can I make Johan happy?","How can I prove that food is more important than drink?"],"correctAnswer":"How can I use my limited money in a way that serves my day well?","feedback":"Correct. Thabo''s choice is an everyday example of economics. He has to decide how to use limited money for a real need. This is not cold maths; it is a human choice."},{"id":"daily-grind-johan-beans","prompt":"Johan must choose between cheaper Robusta beans and smoother Arabica beans that cost more. Which question should guide him best?","choices":["Which beans cost the least today, even if customers enjoy them less?","Which beans sound more professional when I talk about them?","Which beans help me serve customers well and keep the shop healthy?","Which beans make the fastest decision possible?","Which beans will make every customer buy muffins?","Which beans allow me to ignore what customers think?"],"correctAnswer":"Which beans help me serve customers well and keep the shop healthy?","feedback":"Correct. Johan''s choice is not only about cost. He must think about quality, trust, customers, and the future of the business. Business choices are moral choices because they affect people."},{"id":"daily-grind-government-choice","prompt":"The government considers helping local farmers by making imported beans more expensive. What is the difficult part of this decision?","choices":["It may help local farmers but make coffee more expensive for shops and customers","It will make all coffee free for everyone","It only affects farmers and never affects ordinary people","It proves that government decisions are always easy","It means coffee shops will no longer need customers","It removes the need for careful thinking"],"correctAnswer":"It may help local farmers but make coffee more expensive for shops and customers","feedback":"Correct. A decision can help one group while placing pressure on another. This is why public choices must be guided by wisdom, justice, and care for people."},{"id":"daily-grind-bigger-lesson","prompt":"What do Thabo, Johan, and the government all show us about economics?","choices":["Economics is only for experts who understand difficult maths","Economics is mainly about banks and stock markets","Economics is about people, businesses, and governments making choices with what they have","Economics has nothing to do with values or beliefs","Economics is only about choosing the cheapest option","Economics is a machine that works without human hearts or convictions"],"correctAnswer":"Economics is about people, businesses, and governments making choices with what they have","feedback":"Correct. Economics studies real choices. And because real choices come from what people value, trust, love, and believe, our morals and faith should stand at the centre of our economic life."}],"conclusion":"Thabo''s coffee choice, Johan''s business decision, and the government''s farming policy all point to one lesson: economics is not only about money, banks, graphs, or difficult maths. It is about the choices people make with what they have. Because choices are shaped by what people value and believe, our morals and faith must guide our economic life."}},{"id":"level-1-session-1-the-daily-grind-ordinary-business-life","kind":"customHtml","title":"Step 2: The Ordinary Business of Life","body":"\n  <style>\n    :root {\n      color-scheme: light;\n      --paper: #f7f3e8;\n      --cream: #e8d8b8;\n      --forest: #234638;\n      --ubuntu: #4f6b3a;\n      --leaf: #7c8f5a;\n      --gold: #b99245;\n      --amber: #d99a3d;\n      --kraft: #9a6b3f;\n      --deep-kraft: #5b3a24;\n      --ink: #17130f;\n      --muted: #5d6659;\n    }\n\n    * {\n      box-sizing: border-box;\n    }\n\n    body {\n      margin: 0;\n      font-family: \"Segoe UI\", system-ui, sans-serif;\n      background:\n        linear-gradient(180deg, rgba(247, 243, 232, 0.98), rgba(232, 216, 184, 0.74)),\n        radial-gradient(circle at 16% 10%, rgba(217, 154, 61, 0.16), transparent 32%);\n      color: var(--ink);\n    }\n\n    .rich-step {\n      min-height: 100vh;\n      padding: clamp(18px, 4vw, 34px);\n    }\n\n    h2,\n    h3,\n    p {\n      margin-top: 0;\n    }\n\n    h2 {\n      margin-bottom: 10px;\n      color: var(--forest);\n      font-size: clamp(1.65rem, 4vw, 2.6rem);\n      line-height: 1.08;\n    }\n\n    h3 {\n      margin-bottom: 8px;\n      color: var(--forest);\n      font-size: 1.08rem;\n    }\n\n    p {\n      color: var(--muted);\n      line-height: 1.62;\n    }\n\n    .intro {\n      width: 100%;\n      max-width: none;\n      margin-bottom: 22px;\n      font-size: 1rem;\n    }\n\n    .eyebrow {\n      margin-bottom: 8px;\n      color: var(--gold);\n      font-size: 0.78rem;\n      font-weight: 800;\n      letter-spacing: 0;\n      text-transform: uppercase;\n    }\n\n    .grid {\n      display: grid;\n      grid-template-columns: repeat(auto-fit, minmax(220px, 1fr));\n      gap: 14px;\n      margin: 18px 0;\n    }\n\n    .card,\n    .callout,\n    .comparison {\n      border: 1px solid rgba(91, 58, 36, 0.18);\n      border-radius: 8px;\n      background: rgba(255, 255, 255, 0.56);\n      box-shadow: 0 16px 34px rgba(91, 58, 36, 0.12);\n    }\n\n    .card {\n      padding: 16px;\n    }\n\n    .card strong {\n      display: block;\n      margin-bottom: 6px;\n      color: var(--deep-kraft);\n      font-size: 0.86rem;\n      text-transform: uppercase;\n    }\n\n    .pill {\n      display: inline-flex;\n      min-height: 28px;\n      align-items: center;\n      margin: 8px 6px 0 0;\n      padding: 0 10px;\n      border-radius: 999px;\n      background: rgba(124, 143, 90, 0.22);\n      color: var(--forest);\n      font-size: 0.82rem;\n      font-weight: 750;\n    }\n\n    .callout {\n      margin-top: 18px;\n      padding: 16px;\n      border-left: 5px solid var(--gold);\n      background: rgba(217, 154, 61, 0.1);\n    }\n\n    .comparison {\n      display: grid;\n      grid-template-columns: minmax(0, 1fr) minmax(0, 1fr);\n      overflow: hidden;\n    }\n\n    .comparison div {\n      padding: 14px;\n    }\n\n    .comparison div:first-child {\n      border-right: 1px solid rgba(91, 58, 36, 0.18);\n      background: rgba(35, 70, 56, 0.08);\n    }\n\n    ul {\n      display: grid;\n      gap: 9px;\n      margin: 10px 0 0;\n      padding-left: 18px;\n      color: var(--muted);\n      line-height: 1.5;\n    }\n\n    textarea {\n      width: 100%;\n      min-height: 150px;\n      margin-top: 12px;\n      border: 1px solid rgba(91, 58, 36, 0.22);\n      border-radius: 8px;\n      padding: 12px 14px;\n      background: rgba(255, 255, 255, 0.72);\n      color: var(--ink);\n      font: inherit;\n      line-height: 1.55;\n      resize: vertical;\n      box-shadow: inset 0 1px 0 rgba(255, 255, 255, 0.72);\n    }\n\n    textarea:focus {\n      outline: 3px solid rgba(185, 146, 69, 0.28);\n      outline-offset: 2px;\n    }\n\n    .market-theology-page {\n      display: grid;\n      gap: clamp(18px, 3vw, 26px);\n      align-items: stretch;\n      justify-items: center;\n    }\n\n    .audio-discussion {\n      width: min(100%, 1180px);\n      display: grid;\n      gap: 10px;\n      justify-items: center;\n      margin-inline: auto;\n    }\n\n    .audio-discussion-copy {\n      margin: 0;\n      color: var(--forest);\n      font-size: clamp(1rem, 1.6vw, 1.18rem);\n      font-weight: 800;\n      text-align: center;\n    }\n\n    .audio-discussion-toggle {\n      position: absolute;\n      width: 1px;\n      height: 1px;\n      opacity: 0;\n      pointer-events: none;\n    }\n\n    .audio-discussion-button {\n      width: min(100%, 480px);\n      display: block;\n      padding: 0;\n      border: 0;\n      border-radius: 0;\n      background: transparent;\n      box-shadow: none;\n      cursor: pointer;\n    }\n\n    .audio-discussion-button img {\n      display: block;\n      width: 100%;\n      height: auto;\n      object-fit: contain;\n      filter: drop-shadow(0 16px 22px rgba(91, 58, 36, 0.16));\n      transition: transform 180ms ease;\n    }\n\n    .audio-discussion-button:hover img {\n      transform: translateY(-2px);\n    }\n\n    .audio-popup {\n      position: fixed;\n      inset: 0;\n      z-index: 140;\n      display: none;\n      padding: clamp(18px, 3vw, 32px);\n      background: rgba(23, 19, 15, 0.94);\n    }\n\n    .audio-discussion-toggle:checked ~ .audio-popup {\n      display: grid;\n    }\n\n    .audio-popup-scrim {\n      position: absolute;\n      inset: 0;\n      cursor: pointer;\n    }\n\n    .audio-popup-panel {\n      position: relative;\n      z-index: 1;\n      width: min(100%, 980px);\n      min-height: min(72vh, 680px);\n      display: grid;\n      gap: clamp(20px, 4vw, 34px);\n      align-content: center;\n      justify-self: center;\n      align-self: center;\n      border: 1px solid rgba(232, 216, 184, 0.22);\n      border-radius: 8px;\n      padding: clamp(22px, 4vw, 48px);\n      background:\n        linear-gradient(145deg, rgba(247, 243, 232, 0.96), rgba(232, 216, 184, 0.84)),\n        radial-gradient(circle at 50% 0%, rgba(185, 146, 69, 0.18), transparent 42%);\n      box-shadow: 0 28px 70px rgba(0, 0, 0, 0.42);\n    }\n\n    .soundwave {\n      min-height: clamp(150px, 24vw, 240px);\n      display: flex;\n      gap: clamp(7px, 1.3vw, 14px);\n      align-items: center;\n      justify-content: center;\n      padding: clamp(16px, 3vw, 30px);\n    }\n\n    .soundwave span {\n      width: clamp(7px, 1.2vw, 13px);\n      height: 42%;\n      border-radius: 999px;\n      background: linear-gradient(180deg, var(--gold), var(--forest));\n      animation: soundwave-rise 1.05s ease-in-out infinite;\n      box-shadow: 0 10px 20px rgba(91, 58, 36, 0.16);\n    }\n\n    .soundwave span:nth-child(2) {\n      animation-delay: -0.86s;\n    }\n\n    .soundwave span:nth-child(3) {\n      animation-delay: -0.68s;\n    }\n\n    .soundwave span:nth-child(4) {\n      animation-delay: -0.5s;\n    }\n\n    .soundwave span:nth-child(5) {\n      animation-delay: -0.32s;\n    }\n\n    .soundwave span:nth-child(6) {\n      animation-delay: -0.14s;\n    }\n\n    .soundwave span:nth-child(7) {\n      animation-delay: -0.76s;\n    }\n\n    .soundwave span:nth-child(8) {\n      animation-delay: -0.58s;\n    }\n\n    .soundwave span:nth-child(9) {\n      animation-delay: -0.4s;\n    }\n\n    .soundwave span:nth-child(10) {\n      animation-delay: -0.22s;\n    }\n\n    @keyframes soundwave-rise {\n      0%,\n      100% {\n        transform: scaleY(0.34);\n      }\n\n      50% {\n        transform: scaleY(1);\n      }\n    }\n\n    .audio-popup audio {\n      width: min(100%, 760px);\n      justify-self: center;\n      accent-color: var(--forest);\n    }\n\n    .audio-popup-close {\n      min-height: 42px;\n      width: fit-content;\n      display: inline-flex;\n      align-items: center;\n      justify-content: center;\n      justify-self: center;\n      border: 1px solid rgba(35, 70, 56, 0.18);\n      border-radius: 8px;\n      padding: 0 16px;\n      background: var(--forest);\n      color: var(--paper);\n      font-weight: 800;\n      cursor: pointer;\n      transition:\n        background 160ms ease,\n        transform 160ms ease;\n    }\n\n    .audio-popup-close:hover {\n      background: #1d3a2f;\n      transform: translateY(-1px);\n    }\n\n    .wrong-thinking-section {\n      width: min(100%, 1180px);\n      display: grid;\n      gap: clamp(16px, 2.6vw, 24px);\n      margin-inline: auto;\n    }\n\n    .wrong-thinking-section h2 {\n      margin: 0;\n      color: var(--forest);\n      font-size: clamp(1.75rem, 4vw, 2.7rem);\n      line-height: 1.08;\n    }\n\n    .scholars-heading {\n      margin: clamp(6px, 1.4vw, 12px) 0 0;\n      color: var(--deep-kraft);\n      font-size: clamp(1.2rem, 2.4vw, 1.7rem);\n      font-weight: 850;\n      text-align: center;\n    }\n\n    .wrong-thinking-images,\n    .wrong-card-grid {\n      display: grid;\n      grid-template-columns: repeat(2, minmax(0, 1fr));\n      gap: clamp(14px, 2.4vw, 22px);\n      width: 100%;\n    }\n\n    .wrong-thinking-image {\n      border: 1px solid rgba(91, 58, 36, 0.18);\n      border-radius: 8px;\n      padding: clamp(10px, 1.8vw, 18px);\n      background: rgba(255, 255, 255, 0.58);\n      box-shadow: 0 18px 36px rgba(91, 58, 36, 0.14);\n    }\n\n    .wrong-thinking-image:nth-child(1) {\n      background:\n        linear-gradient(145deg, rgba(210, 225, 194, 0.96), rgba(124, 143, 90, 0.34)),\n        radial-gradient(circle at 12% 0%, rgba(35, 70, 56, 0.16), transparent 42%);\n    }\n\n    .wrong-thinking-image:nth-child(2) {\n      background:\n        linear-gradient(145deg, rgba(236, 214, 151, 0.96), rgba(217, 154, 61, 0.28)),\n        radial-gradient(circle at 92% 0%, rgba(91, 58, 36, 0.14), transparent 42%);\n    }\n\n    .wrong-thinking-image {\n      margin: 0;\n      overflow: hidden;\n    }\n\n    .wrong-thinking-image img {\n      display: block;\n      width: 100%;\n      height: 100%;\n      min-height: clamp(280px, 34vw, 430px);\n      object-fit: contain;\n      border-radius: 6px;\n      background: rgba(247, 243, 232, 0.28);\n    }\n\n    .wrong-flip-card {\n      position: relative;\n      aspect-ratio: 4 / 3;\n      min-height: 0;\n    }\n\n    .wrong-flip-toggle,\n    .wrong-slide-toggle {\n      position: absolute;\n      width: 1px;\n      height: 1px;\n      opacity: 0;\n      pointer-events: none;\n    }\n\n    .wrong-flip-cover {\n      position: absolute;\n      inset: 0;\n      overflow: hidden;\n      border-radius: 0;\n      background: transparent;\n      box-shadow: none;\n      cursor: pointer;\n    }\n\n    .wrong-flip-cover img {\n      display: block;\n      width: 100%;\n      height: 100%;\n      object-fit: contain;\n      object-position: center;\n      transition: transform 220ms ease;\n    }\n\n    .wrong-flip-cover:hover img {\n      transform: none;\n    }\n\n    .wrong-flip-cta,\n    .wrong-popup-close,\n    .wrong-carousel-controls label {\n      min-height: 42px;\n      display: inline-flex;\n      align-items: center;\n      justify-content: center;\n      border: 1px solid rgba(35, 70, 56, 0.18);\n      border-radius: 8px;\n      background: var(--forest);\n      color: var(--paper);\n      font-weight: 800;\n      cursor: pointer;\n      transition:\n        background 160ms ease,\n        transform 160ms ease;\n    }\n\n    .wrong-flip-cta {\n      position: absolute;\n      right: clamp(14px, 2vw, 20px);\n      bottom: clamp(14px, 2vw, 20px);\n      padding: 0 18px;\n      background: rgba(35, 70, 56, 0.92);\n      box-shadow: 0 12px 26px rgba(23, 19, 15, 0.2);\n    }\n\n    .wrong-flip-cta:hover,\n    .wrong-popup-close:hover,\n    .wrong-carousel-controls label:hover {\n      background: #1d3a2f;\n      transform: translateY(-1px);\n    }\n\n    .wrong-carousel-popup {\n      position: fixed;\n      inset: 0;\n      z-index: 120;\n      display: none;\n      padding: clamp(12px, 2vw, 24px);\n      background: rgba(23, 19, 15, 0.94);\n    }\n\n    .wrong-flip-toggle:checked ~ .wrong-carousel-popup {\n      display: grid;\n    }\n\n    .wrong-popup-scrim {\n      position: absolute;\n      inset: 0;\n      cursor: pointer;\n    }\n\n    .wrong-popup-panel {\n      position: relative;\n      z-index: 1;\n      min-width: 0;\n      min-height: 0;\n      display: grid;\n      border-radius: 8px;\n      overflow: hidden;\n      background: rgba(247, 243, 232, 0.08);\n    }\n\n    .wrong-carousel {\n      position: relative;\n      min-height: 0;\n      display: grid;\n      grid-template-rows: minmax(0, 1fr) auto;\n      gap: 12px;\n    }\n\n    .wrong-carousel-window {\n      min-height: 0;\n      overflow: hidden;\n      border: 0;\n      border-radius: 8px;\n      background: rgba(247, 243, 232, 0.08);\n    }\n\n    .wrong-carousel-track {\n      display: flex;\n      width: 200%;\n      height: 100%;\n      transition: transform 320ms ease;\n    }\n\n    .wrong-carousel-slide {\n      flex: 0 0 50%;\n      margin: 0;\n    }\n\n    .wrong-carousel-slide img {\n      display: block;\n      width: 100%;\n      height: 100%;\n      object-fit: contain;\n      padding: 0;\n    }\n\n    .wrong-slide-two-toggle:checked ~ .wrong-carousel-window .wrong-carousel-track {\n      transform: translateX(-50%);\n    }\n\n    .wrong-carousel-controls {\n      display: grid;\n      grid-template-columns: minmax(52px, 0.12fr) minmax(52px, 0.12fr) auto;\n      gap: 10px;\n      align-items: center;\n      justify-content: center;\n    }\n\n    .wrong-carousel-controls label {\n      min-width: 42px;\n      padding: 0 12px;\n      background: rgba(35, 70, 56, 0.82);\n      font-size: 0.92rem;\n    }\n\n    .wrong-slide-one-toggle:checked ~ .wrong-carousel-controls .wrong-dot-one,\n    .wrong-slide-two-toggle:checked ~ .wrong-carousel-controls .wrong-dot-two {\n      background: var(--gold);\n      color: var(--ink);\n    }\n\n    .wrong-popup-close {\n      padding: 0 14px;\n      background: rgba(91, 58, 36, 0.86);\n      color: var(--paper);\n    }\n\n    .market-image-story {\n      width: min(100%, 1180px);\n      margin-inline: auto;\n      border: 1px solid rgba(91, 58, 36, 0.18);\n      border-radius: 8px;\n      padding: clamp(18px, 3vw, 30px);\n      background:\n        linear-gradient(145deg, rgba(247, 243, 232, 0.96), rgba(232, 216, 184, 0.68)),\n        radial-gradient(circle at 10% 0%, rgba(185, 146, 69, 0.14), transparent 38%);\n      box-shadow: 0 20px 42px rgba(91, 58, 36, 0.14);\n    }\n\n    .market-image-story::after {\n      content: \"\";\n      display: block;\n      clear: both;\n    }\n\n    .market-theology-visual {\n      float: right;\n      width: min(46%, 520px);\n      margin: 0 0 clamp(16px, 2.4vw, 26px) clamp(20px, 3vw, 38px);\n      border: 1px solid rgba(91, 58, 36, 0.18);\n      border-radius: 8px;\n      overflow: hidden;\n      background: rgba(255, 255, 255, 0.62);\n      box-shadow: 0 18px 34px rgba(91, 58, 36, 0.16);\n    }\n\n    .market-theology-visual img {\n      display: block;\n      width: 100%;\n      height: auto;\n      object-fit: contain;\n    }\n\n    .market-image-story p {\n      margin: 0 0 clamp(12px, 1.8vw, 18px);\n      color: var(--muted);\n      font-size: clamp(1rem, 1.45vw, 1.16rem);\n      line-height: 1.66;\n    }\n\n    .market-image-story p:last-child {\n      margin-bottom: 0;\n    }\n\n    .market-image-story .closing-line {\n      color: var(--forest);\n      font-weight: 750;\n    }\n\n    .scripture-reflection {\n      width: min(100%, 1180px);\n      margin-inline: auto;\n    }\n\n    .value-bars {\n      display: grid;\n      gap: 12px;\n      margin: 18px 0;\n    }\n\n    .value-row {\n      display: grid;\n      grid-template-columns: minmax(98px, 0.32fr) minmax(0, 1fr);\n      gap: 12px;\n      align-items: center;\n      color: var(--deep-kraft);\n      font-size: 0.9rem;\n      font-weight: 750;\n    }\n\n    .value-track {\n      min-height: 22px;\n      overflow: hidden;\n      border: 1px solid rgba(91, 58, 36, 0.16);\n      border-radius: 999px;\n      background: rgba(255, 255, 255, 0.58);\n    }\n\n    .value-fill {\n      display: flex;\n      min-height: 22px;\n      align-items: center;\n      justify-content: flex-end;\n      padding-right: 10px;\n      border-radius: 999px;\n      background: linear-gradient(90deg, var(--leaf), var(--gold));\n      color: var(--paper);\n      font-size: 0.78rem;\n      font-weight: 800;\n    }\n\n    .choice-list {\n      display: grid;\n      gap: 12px;\n      margin-top: 14px;\n    }\n\n    .choice-list .card {\n      display: grid;\n      gap: 6px;\n      box-shadow: none;\n    }\n\n    .ordinary-art-page {\n      min-height: calc(100vh - 120px);\n      display: grid;\n      gap: clamp(24px, 4vw, 42px);\n      align-content: start;\n      border-radius: 8px;\n      background:\n        linear-gradient(180deg, rgba(247, 243, 232, 0.84), rgba(247, 243, 232, 0.94)),\n        radial-gradient(circle at 12% 0%, rgba(217, 154, 61, 0.12), transparent 34%);\n    }\n\n    .ordinary-story {\n      color: #76604f;\n    }\n\n    .ordinary-story::after {\n      content: \"\";\n      display: block;\n      clear: both;\n    }\n\n    .ordinary-hero {\n      float: left;\n      width: min(59%, 740px);\n      margin: 0 clamp(24px, 3vw, 42px) 18px 0;\n      border-radius: 8px;\n      object-fit: contain;\n      box-shadow: 0 18px 34px rgba(91, 58, 36, 0.16);\n    }\n\n    .ordinary-copy {\n      max-width: none;\n    }\n\n    .ordinary-copy p {\n      margin: 0 0 clamp(12px, 1.6vw, 18px);\n      color: #76604f;\n      font-size: clamp(1.08rem, 1.65vw, 1.38rem);\n      line-height: 1.62;\n    }\n\n    .ordinary-copy p:last-child {\n      margin-bottom: 0;\n    }\n\n    .ordinary-copy .ordinary-small {\n      max-width: 72ch;\n      margin-top: clamp(10px, 1.6vw, 18px);\n      padding-top: clamp(10px, 1.4vw, 16px);\n      border-top: 1px solid rgba(118, 96, 79, 0.18);\n      font-size: clamp(0.98rem, 1.35vw, 1.14rem);\n      line-height: 1.58;\n    }\n\n    .transparent-quote-row {\n      display: grid;\n      grid-template-columns: repeat(2, minmax(280px, 1fr));\n      gap: clamp(34px, 8vw, 110px);\n      align-items: end;\n      margin: 0;\n      padding: clamp(12px, 2.2vw, 20px) clamp(8px, 2vw, 18px);\n      border-radius: 8px;\n      background:\n        linear-gradient(90deg, rgba(247, 243, 232, 0.18), rgba(232, 216, 184, 0.32), rgba(247, 243, 232, 0.18));\n    }\n\n    .transparent-quote {\n      margin: 0;\n      border: 0;\n      background: transparent;\n      box-shadow: none;\n      display: grid;\n      place-items: end center;\n    }\n\n    .transparent-quote img {\n      display: block;\n      width: 100%;\n      max-width: 640px;\n      height: clamp(130px, 15vw, 178px);\n      object-fit: contain;\n      mix-blend-mode: multiply;\n      filter: drop-shadow(0 10px 12px rgba(91, 58, 36, 0.12));\n    }\n\n    .economics-step-page {\n      display: grid;\n      gap: clamp(18px, 3vw, 26px);\n      border: 1px solid rgba(91, 58, 36, 0.18);\n      border-radius: 8px;\n      padding: clamp(18px, 3vw, 28px);\n      background:\n        linear-gradient(145deg, rgba(247, 243, 232, 0.96), rgba(232, 216, 184, 0.72)),\n        radial-gradient(circle at 15% 0%, rgba(217, 154, 61, 0.14), transparent 36%);\n      box-shadow: 0 22px 48px rgba(91, 58, 36, 0.16);\n    }\n\n    .economics-step-header {\n      display: flex;\n      gap: 16px;\n      align-items: flex-start;\n      justify-content: space-between;\n    }\n\n    .economics-step-header h2,\n    .economics-step-header p {\n      margin: 0;\n    }\n\n    .economics-step-header h2 {\n      margin-top: 5px;\n      color: var(--forest);\n      font-size: clamp(1.65rem, 4vw, 2.55rem);\n      line-height: 1.08;\n    }\n\n    .completion-icon {\n      flex: 0 0 auto;\n      width: 36px;\n      height: 36px;\n      display: grid;\n      place-items: center;\n      border: 1px solid rgba(185, 146, 69, 0.44);\n      border-radius: 8px;\n      background: rgba(247, 243, 232, 0.72);\n      color: var(--forest);\n      font-weight: 850;\n      box-shadow: 0 10px 20px rgba(91, 58, 36, 0.1);\n    }\n\n    .economics-teaching-panel {\n      border: 1px solid rgba(91, 58, 36, 0.16);\n      border-radius: 8px;\n      padding: clamp(18px, 3vw, 28px);\n      background:\n        linear-gradient(180deg, rgba(247, 243, 232, 0.92), rgba(255, 255, 255, 0.55)),\n        radial-gradient(circle at 85% 8%, rgba(124, 143, 90, 0.1), transparent 34%);\n      box-shadow: 0 18px 38px rgba(91, 58, 36, 0.12);\n    }\n\n    .economics-hero-layout {\n      display: grid;\n      grid-template-columns: minmax(280px, 0.9fr) minmax(380px, 1.1fr);\n      gap: clamp(18px, 3vw, 28px);\n      align-items: stretch;\n      margin-top: clamp(14px, 2vw, 18px);\n    }\n\n    .economics-hero-copy {\n      display: grid;\n      grid-template-rows: minmax(0, 1fr) minmax(0, 1fr);\n      gap: clamp(16px, 2.4vw, 22px);\n      min-width: 0;\n    }\n\n    .economics-hero-copy .teaching-section {\n      display: grid;\n      align-content: center;\n      margin-top: 0;\n    }\n\n    .economics-square-image {\n      display: block;\n      width: 100%;\n      height: 100%;\n      min-height: clamp(520px, 58vw, 650px);\n      margin: 0;\n      border: 1px solid rgba(91, 58, 36, 0.18);\n      border-radius: 8px;\n      object-fit: cover;\n      object-position: center;\n      background: var(--cream);\n      box-shadow: 0 18px 34px rgba(91, 58, 36, 0.18);\n    }\n\n    .teaching-section {\n      margin-top: clamp(16px, 2.5vw, 22px);\n      overflow: hidden;\n      border: 1px solid rgba(91, 58, 36, 0.13);\n      border-left: 4px solid rgba(185, 146, 69, 0.72);\n      border-radius: 8px;\n      padding: clamp(12px, 1.8vw, 16px) clamp(14px, 2vw, 18px);\n      background:\n        linear-gradient(145deg, rgba(255, 255, 255, 0.46), rgba(247, 243, 232, 0.7)),\n        radial-gradient(circle at 100% 0%, rgba(185, 146, 69, 0.1), transparent 34%);\n      box-shadow: 0 12px 26px rgba(91, 58, 36, 0.08);\n    }\n\n    .teaching-section.everyday-life-section {\n      border-left-color: rgba(79, 107, 58, 0.86);\n      background:\n        linear-gradient(145deg, rgba(124, 143, 90, 0.14), rgba(247, 243, 232, 0.76)),\n        radial-gradient(circle at 100% 0%, rgba(79, 107, 58, 0.12), transparent 34%);\n    }\n\n    .teaching-section.misunderstanding-section {\n      border-color: rgba(217, 154, 61, 0.34);\n      border-left-color: var(--amber);\n      background:\n        linear-gradient(145deg, rgba(217, 154, 61, 0.2), rgba(247, 243, 232, 0.78)),\n        radial-gradient(circle at 100% 0%, rgba(154, 107, 63, 0.14), transparent 34%);\n    }\n\n    .teaching-section.misunderstanding-section h3 {\n      color: var(--deep-kraft);\n    }\n\n    .teaching-section.takeaway-section {\n      border-left-color: rgba(35, 70, 56, 0.84);\n      background:\n        linear-gradient(145deg, rgba(35, 70, 56, 0.1), rgba(247, 243, 232, 0.76)),\n        radial-gradient(circle at 100% 0%, rgba(185, 146, 69, 0.12), transparent 34%);\n    }\n\n    .teaching-section:first-of-type {\n      margin-top: 0;\n    }\n\n    .teaching-section h3,\n    .teaching-section p {\n      margin: 0;\n    }\n\n    .teaching-section h3 {\n      margin-bottom: 10px;\n      color: var(--forest);\n      font-size: clamp(1.05rem, 2vw, 1.22rem);\n      line-height: 1.2;\n    }\n\n    .teaching-section p + p {\n      margin-top: 22px;\n    }\n\n    .teaching-section p,\n    .economics-list li {\n      color: var(--deep-kraft);\n      font-size: clamp(0.96rem, 1.55vw, 1.08rem);\n      line-height: 1.72;\n    }\n\n    .economics-list {\n      grid-template-columns: repeat(auto-fit, minmax(210px, 1fr));\n      gap: 8px 18px;\n      margin: 9px 0 0;\n      padding-left: 18px;\n    }\n\n    .economics-visual-card {\n      clear: both;\n      margin: clamp(18px, 3vw, 26px) 0;\n      border: 1px solid rgba(91, 58, 36, 0.16);\n      border-radius: 8px;\n      padding: clamp(10px, 1.8vw, 14px);\n      background:\n        linear-gradient(145deg, rgba(247, 243, 232, 0.86), rgba(255, 255, 255, 0.58)),\n        radial-gradient(circle at 12% 0%, rgba(217, 154, 61, 0.12), transparent 32%);\n      box-shadow: 0 16px 34px rgba(91, 58, 36, 0.12);\n    }\n\n    .economics-visual-card img {\n      display: block;\n      width: 100%;\n      max-height: 520px;\n      object-fit: contain;\n      border-radius: 6px;\n    }\n\n    .quote-card-row,\n    .concept-card-row {\n      display: grid;\n      grid-template-columns: repeat(2, minmax(0, 1fr));\n      gap: clamp(14px, 2.5vw, 20px);\n    }\n\n    .quote-card-row {\n      align-items: stretch;\n    }\n\n    .quote-card {\n      display: grid;\n      place-items: center;\n      border: 1px solid rgba(185, 146, 69, 0.34);\n      border-left: 5px solid var(--gold);\