ay: grid;\n      grid-template-columns: minmax(90px, 0.18fr) minmax(0, 1fr);\n      gap: 12px;\n      align-items: center;\n    }\n\n    .choice-chart-row strong {\n      color: var(--deep-kraft);\n    }\n\n    .choice-chart-tags {\n      display: flex;\n      gap: 8px;\n      flex-wrap: wrap;\n    }\n\n    .choice-chart-tags span {\n      border: 1px solid rgba(79, 107, 58, 0.2);\n      border-radius: 999px;\n      padding: 6px 10px;\n      background: rgba(124, 143, 90, 0.17);\n      color: var(--forest);\n      font-size: 0.86rem;\n      font-weight: 750;\n    }\n\n    .faith-reflection {\n      border-color: rgba(217, 154, 61, 0.44);\n      border-left-color: var(--amber);\n      background:\n        linear-gradient(145deg, rgba(217, 154, 61, 0.13), rgba(247, 243, 232, 0.74));\n    }\n\n    .pillars-page {\n      display: grid;\n      gap: clamp(18px, 3vw, 28px);\n    }\n\n    .pillars-hero {\n      display: grid;\n      gap: 10px;\n      justify-items: center;\n      text-align: center;\n      padding: clamp(18px, 3vw, 28px);\n      border: 1px solid rgba(91, 58, 36, 0.18);\n      border-radius: 8px;\n      background:\n        linear-gradient(145deg, rgba(247, 243, 232, 0.94), rgba(232, 216, 184, 0.7)),\n        radial-gradient(circle at 50% 0%, rgba(217, 154, 61, 0.16), transparent 36%);\n      box-shadow: 0 18px 42px rgba(91, 58, 36, 0.14);\n    }\n\n    .pillars-hero h2 {\n      max-width: 980px;\n      margin: 0;\n      font-family: Georgia, \"Times New Roman\", serif;\n      color: var(--forest);\n      font-size: clamp(2rem, 6vw, 4.4rem);\n      line-height: 1;\n    }\n\n    .pillars-hero p {\n      max-width: 760px;\n      margin: 0;\n      color: var(--deep-kraft);\n      font-size: clamp(0.98rem, 1.5vw, 1.12rem);\n    }\n\n    .pillars-grid {\n      position: relative;\n      display: grid;\n      grid-template-columns: repeat(2, minmax(260px, 1fr));\n      gap: clamp(16px, 2.5vw, 26px);\n      padding: clamp(12px, 2vw, 18px);\n      border-radius: 8px;\n      overflow: visible;\n      background:\n        linear-gradient(180deg, rgba(247, 243, 232, 0.42), rgba(232, 216, 184, 0.36)),\n        radial-gradient(circle at 0% 100%, rgba(185, 146, 69, 0.12), transparent 30%);\n    }\n\n    .pillar-card-shell {\n      position: relative;\n      min-height: clamp(210px, 22vw, 280px);\n      z-index: 0;\n    }\n\n    .pillar-card-shell:has(.pillar-toggle:checked) {\n      z-index: 1000;\n    }\n\n    .pillar-toggle {\n      position: absolute;\n      width: 1px;\n      height: 1px;\n      opacity: 0;\n      pointer-events: none;\n    }\n\n    .pillar-flip-card {\n      position: relative;\n      display: block;\n      width: 100%;\n      height: 100%;\n      min-height: inherit;\n      cursor: pointer;\n      transform-style: preserve-3d;\n      transition:\n        transform 420ms ease,\n        filter 180ms ease;\n    }\n\n    .pillar-toggle:checked + .pillar-flip-card {\n      z-index: 4;\n      transform: translateY(-2px) scale(1.01);\n      filter: drop-shadow(0 24px 30px rgba(91, 58, 36, 0.18));\n    }\n\n    .pillar-toggle:focus-visible + .pillar-flip-card .pillar-face {\n      outline: 3px solid rgba(185, 146, 69, 0.45);\n      outline-offset: 3px;\n    }\n\n    .pillar-face {\n      position: absolute;\n      inset: 0;\n      overflow: hidden;\n      border: 2px solid rgba(185, 146, 69, 0.58);\n      border-radius: 8px;\n      backface-visibility: hidden;\n      box-shadow:\n        0 18px 34px rgba(91, 58, 36, 0.13),\n        inset 0 1px 0 rgba(255, 255, 255, 0.7);\n    }\n\n    .pillar-front {\n      display: grid;\n      grid-template-columns: minmax(112px, 0.42fr) minmax(0, 1fr);\n      gap: clamp(14px, 2vw, 22px);\n      align-items: center;\n      padding: clamp(22px, 3vw, 32px);\n      background:\n        linear-gradient(145deg, rgba(247, 243, 232, 0.96), rgba(232, 216, 184, 0.56)),\n        radial-gradient(circle at 0% 100%, rgba(185, 146, 69, 0.18), transparent 34%);\n    }\n\n    .pillar-icon {\n      display: grid;\n      place-items: center;\n      min-height: 128px;\n      color: var(--gold);\n    }\n\n    .pillar-icon img {\n      display: block;\n      width: min(150px, 100%);\n      height: auto;\n      max-height: 150px;\n      object-fit: contain;\n      filter: drop-shadow(0 10px 10px rgba(91, 58, 36, 0.16));\n    }\n\n    .pillar-front h3,\n    .pillar-front p,\n    .pillar-popup-card h3,\n    .pillar-popup-card p {\n      margin: 0;\n    }\n\n    .pillar-front h3 {\n      color: var(--forest);\n      font-family: Georgia, \"Times New Roman\", serif;\n      font-size: clamp(1.75rem, 3.5vw, 3.15rem);\n      line-height: 1;\n    }\n\n    .pillar-front p {\n      max-width: 30rem;\n      margin-top: 10px;\n      color: var(--deep-kraft);\n      font-size: clamp(0.95rem, 1.35vw, 1.08rem);\n      line-height: 1.35;\n    }\n\n    .pillar-front span {\n      display: inline-flex;\n      width: fit-content;\n      margin-top: 14px;\n      border-radius: 999px;\n      padding: 6px 10px;\n      background: rgba(185, 146, 69, 0.16);\n      color: var(--deep-kraft);\n      font-size: 0.78rem;\n      font-weight: 800;\n      text-transform: uppercase;\n    }\n\n    .pillar-popup {\n      position: fixed;\n      inset: 0;\n      z-index: 9999;\n      isolation: isolate;\n      display: grid;\n      place-items: center;\n      padding: clamp(16px, 4vw, 38px);\n      background: rgba(23, 19, 15, 0.68);\n      backdrop-filter: blur(5px);\n      opacity: 0;\n      pointer-events: none;\n      visibility: hidden;\n      transition:\n        opacity 180ms ease,\n        visibility 180ms ease;\n    }\n\n    .pillar-toggle:checked ~ .pillar-popup {\n      opacity: 1;\n      pointer-events: auto;\n      visibility: visible;\n    }\n\n    .pillar-popup-backdrop {\n      position: absolute;\n      inset: 0;\n      cursor: pointer;\n    }\n\n    .pillar-popup-card {\n      position: relative;\n      z-index: 1;\n      width: min(760px, calc(100vw - 28px));\n      max-height: min(84vh, 680px);\n      display: grid;\n      gap: clamp(14px, 2vw, 18px);\n      overflow: auto;\n      border: 2px solid rgba(185, 146, 69, 0.58);\n      border-radius: 8px;\n      padding: clamp(20px, 3vw, 32px);\n      background:\n        linear-gradient(145deg, #f7f3e8, #f0e5cf),\n        radial-gradient(circle at 100% 0%, rgba(79, 107, 58, 0.12), transparent 36%);\n      box-shadow: 0 34px 90px rgba(23, 19, 15, 0.52);\n      transform: translateY(18px) rotateX(4deg) scale(0.97);\n      transform-origin: center;\n      transition: transform 220ms ease;\n    }\n\n    .pillar-toggle:checked ~ .pillar-popup .pillar-popup-card {\n      transform: translateY(0) rotateX(0) scale(1);\n    }\n\n    .pillar-popup-close {\n      position: sticky;\n      top: 0;\n      justify-self: end;\n      border: 1px solid rgba(91, 58, 36, 0.2);\n      border-radius: 999px;\n      padding: 7px 12px;\n      background: #f7f3e8;\n      color: var(--deep-kraft);\n      cursor: pointer;\n      font-size: 0.78rem;\n      font-weight: 850;\n      text-transform: uppercase;\n      box-shadow: 0 8px 16px rgba(91, 58, 36, 0.12);\n    }\n\n    .pillar-popup-card strong {\n      color: var(--gold);\n      font-size: 0.76rem;\n      text-transform: uppercase;\n    }\n\n    .pillar-popup-card h3 {\n      color: var(--forest);\n      max-width: 100%;\n      font-size: clamp(1.55rem, 3vw, 2.25rem);\n      line-height: 1.16;\n      text-wrap: balance;\n    }\n\n    .pillar-popup-card p {\n      color: var(--muted);\n      max-width: 68ch;\n      font-size: clamp(1.04rem, 1.55vw, 1.18rem);\n      line-height: 1.65;\n    }\n\n    .complete-button {\n      display: inline-flex;\n      min-height: 42px;\n      align-items: center;\n      justify-content: center;\n      margin-top: 22px;\n      padding: 0 16px;\n      border: 1px solid var(--forest);\n      border-radius: 8px;\n      background: linear-gradient(145deg, var(--forest), var(--ubuntu));\n      color: var(--paper);\n      font: inherit;\n      font-weight: 750;\n      cursor: pointer;\n      box-shadow: 0 12px 24px rgba(35, 70, 56, 0.22);\n      transition:\n        background 160ms ease,\n        transform 160ms ease,\n        box-shadow 160ms ease;\n    }\n\n    .complete-button:hover {\n      background: linear-gradient(145deg, #1d3a2f, var(--forest));\n      box-shadow: 0 14px 28px rgba(35, 70, 56, 0.26);\n      transform: translateY(-1px);\n    }\n\n    @media (max-width: 640px) {\n      .comparison {\n        grid-template-columns: 1fr;\n      }\n\n      .comparison div:first-child {\n        border-right: 0;\n        border-bottom: 1px solid rgba(91, 58, 36, 0.18);\n      }\n\n      .value-row {\n        grid-template-columns: 1fr;\n        gap: 6px;\n      }\n\n      .ordinary-hero {\n        float: none;\n        width: 100%;\n        margin: 0 0 18px;\n      }\n\n      .ordinary-copy p {\n        font-size: 1rem;\n        line-height: 1.56;\n      }\n\n      .market-theology-visual {\n        float: none;\n        width: 100%;\n        margin: 0 0 18px;\n      }\n\n      .audio-discussion-button {\n        width: min(100%, 360px);\n      }\n\n      .audio-popup-panel {\n        min-height: min(72vh, 560px);\n        padding: 18px;\n      }\n\n      .soundwave {\n        min-height: 130px;\n      }\n\n      .wrong-thinking-images,\n      .wrong-card-grid {\n        grid-template-columns: 1fr;\n      }\n\n      .wrong-thinking-image img {\n        min-height: 0;\n      }\n\n      .wrong-flip-card {\n        min-height: 0;\n      }\n\n      .market-image-story p {\n        font-size: 1rem;\n        line-height: 1.58;\n      }\n\n      .transparent-quote-row {\n        grid-template-columns: 1fr;\n      }\n\n      .economics-step-header {\n        align-items: flex-start;\n      }\n\n      .economics-hero-layout {\n        grid-template-columns: 1fr;\n      }\n\n      .economics-square-image {\n        height: auto;\n        min-height: 0;\n        object-fit: contain;\n      }\n\n      .quote-card-row,\n      .concept-card-row {\n        grid-template-columns: 1fr;\n      }\n\n      .pillars-grid {\n        grid-template-columns: 1fr;\n      }\n\n      .pillar-card-shell {\n        min-height: 250px;\n      }\n\n      .pillar-front {\n        grid-template-columns: 1fr;\n        justify-items: center;\n        text-align: center;\n      }\n\n      .choice-chart-row {\n        grid-template-columns: 1fr;\n        gap: 7px;\n      }\n    }\n  </style>\n  <main class=\"rich-step\" data-rich-lesson-step>\n    \n      <p class=\"eyebrow\">Interactive exploration</p>\n      <h2>The Ordinary Business of Life</h2>\n      <p class=\"intro\">\n        Economics is the art of making the most of life. Every transaction involves deeper questions of value,\n        cost, preference, justice, and faith.\n      </p>\n      <div class=\"grid\">\n        <section class=\"card\">\n          <strong>1. The Consumer: Thabo</strong>\n          <h3>Muffin combo or fancy latte?</h3>\n          <p>Thabo has R50. A muffin combo costs R49, while a fancy latte costs R45. His decision is not only about price; it is about what will serve his real day well.</p>\n          <span class=\"pill\">Need</span><span class=\"pill\">Preference</span><span class=\"pill\">Limited money</span>\n        </section>\n        <section class=\"card\">\n          <strong>2. The Producer: Johan</strong>\n          <h3>Cheap Robusta or premium Arabica?</h3>\n          <p>Johan must choose between higher margins and higher quality. Business decisions are moral decisions because they affect trust, customers, workers, and the future.</p>\n          <span class=\"pill\">Quality</span><span class=\"pill\">Profit</span><span class=\"pill\">Trust</span>\n        </section>\n        <section class=\"card\">\n          <strong>3. The Government</strong>\n          <h3>Tax, protect, or subsidise?</h3>\n          <p>Public policy can help one group while placing pressure on another. Good economic decisions need wisdom, justice, and care for ordinary people.</p>\n          <span class=\"pill\">Public good</span><span class=\"pill\">Trade-offs</span><span class=\"pill\">Justice</span>\n        </section>\n      </div>\n      <div class=\"callout\">\n        <h3>Reflect</h3>\n        <p>Do these choices treat people merely as consumers and producers, or as image-bearers of God?</p>\n      </div>\n    \n    <button class=\"complete-button\" data-classroom-complete data-score=\"5\" data-max-score=\"5\">Continue</button>\n  </main>\n"},{"id":"level-1-session-1-the-daily-grind-economics-everyday-choices","kind":"customHtml","title":"Step 3: Understanding Economics in Everyday Life","body":"\n  <style>\n    :root {\n      color-scheme: light;\n      --paper: #f7f3e8;\n      --cream: #e8d8b8;\n      --forest: #234638;\n      --ubuntu: #4f6b3a;\n      --leaf: #7c8f5a;\n      --gold: #b99245;\n      --amber: #d99a3d;\n      --kraft: #9a6b3f;\n      --deep-kraft: #5b3a24;\n      --ink: #17130f;\n      --muted: #5d6659;\n    }\n\n    * {\n      box-sizing: border-box;\n    }\n\n    body {\n      margin: 0;\n      font-family: \"Segoe UI\", system-ui, sans-serif;\n      background:\n        linear-gradient(180deg, rgba(247, 243, 232, 0.98), rgba(232, 216, 184, 0.74)),\n        radial-gradient(circle at 16% 10%, rgba(217, 154, 61, 0.16), transparent 32%);\n      color: var(--ink);\n    }\n\n    .rich-step {\n      min-height: 100vh;\n      padding: clamp(18px, 4vw, 34px);\n    }\n\n    h2,\n    h3,\n    p {\n      margin-top: 0;\n    }\n\n    h2 {\n      margin-bottom: 10px;\n      color: var(--forest);\n      font-size: clamp(1.65rem, 4vw, 2.6rem);\n      line-height: 1.08;\n    }\n\n    h3 {\n      margin-bottom: 8px;\n      color: var(--forest);\n      font-size: 1.08rem;\n    }\n\n    p {\n      color: var(--muted);\n      line-height: 1.62;\n    }\n\n    .intro {\n      width: 100%;\n      max-width: none;\n      margin-bottom: 22px;\n      font-size: 1rem;\n    }\n\n    .eyebrow {\n      margin-bottom: 8px;\n      color: var(--gold);\n      font-size: 0.78rem;\n      font-weight: 800;\n      letter-spacing: 0;\n      text-transform: uppercase;\n    }\n\n    .grid {\n      display: grid;\n      grid-template-columns: repeat(auto-fit, minmax(220px, 1fr));\n      gap: 14px;\n      margin: 18px 0;\n    }\n\n    .card,\n    .callout,\n    .comparison {\n      border: 1px solid rgba(91, 58, 36, 0.18);\n      border-radius: 8px;\n      background: rgba(255, 255, 255, 0.56);\n      box-shadow: 0 16px 34px rgba(91, 58, 36, 0.12);\n    }\n\n    .card {\n      padding: 16px;\n    }\n\n    .card strong {\n      display: block;\n      margin-bottom: 6px;\n      color: var(--deep-kraft);\n      font-size: 0.86rem;\n      text-transform: uppercase;\n    }\n\n    .pill {\n      display: inline-flex;\n      min-height: 28px;\n      align-items: center;\n      margin: 8px 6px 0 0;\n      padding: 0 10px;\n      border-radius: 999px;\n      background: rgba(124, 143, 90, 0.22);\n      color: var(--forest);\n      font-size: 0.82rem;\n      font-weight: 750;\n    }\n\n    .callout {\n      margin-top: 18px;\n      padding: 16px;\n      border-left: 5px solid var(--gold);\n      background: rgba(217, 154, 61, 0.1);\n    }\n\n    .comparison {\n      display: grid;\n      grid-template-columns: minmax(0, 1fr) minmax(0, 1fr);\n      overflow: hidden;\n    }\n\n    .comparison div {\n      padding: 14px;\n    }\n\n    .comparison div:first-child {\n      border-right: 1px solid rgba(91, 58, 36, 0.18);\n      background: rgba(35, 70, 56, 0.08);\n    }\n\n    ul {\n      display: grid;\n      gap: 9px;\n      margin: 10px 0 0;\n      padding-left: 18px;\n      color: var(--muted);\n      line-height: 1.5;\n    }\n\n    textarea {\n      width: 100%;\n      min-height: 150px;\n      margin-top: 12px;\n      border: 1px solid rgba(91, 58, 36, 0.22);\n      border-radius: 8px;\n      padding: 12px 14px;\n      background: rgba(255, 255, 255, 0.72);\n      color: var(--ink);\n      font: inherit;\n      line-height: 1.55;\n      resize: vertical;\n      box-shadow: inset 0 1px 0 rgba(255, 255, 255, 0.72);\n    }\n\n    textarea:focus {\n      outline: 3px solid rgba(185, 146, 69, 0.28);\n      outline-offset: 2px;\n    }\n\n    .market-theology-page {\n      display: grid;\n      gap: clamp(18px, 3vw, 26px);\n      align-items: stretch;\n      justify-items: center;\n    }\n\n    .audio-discussion {\n      width: min(100%, 1180px);\n      display: grid;\n      gap: 10px;\n      justify-items: center;\n      margin-inline: auto;\n    }\n\n    .audio-discussion-copy {\n      margin: 0;\n      color: var(--forest);\n      font-size: clamp(1rem, 1.6vw, 1.18rem);\n      font-weight: 800;\n      text-align: center;\n    }\n\n    .audio-discussion-toggle {\n      position: absolute;\n      width: 1px;\n      height: 1px;\n      opacity: 0;\n      pointer-events: none;\n    }\n\n    .audio-discussion-button {\n      width: min(100%, 480px);\n      display: block;\n      padding: 0;\n      border: 0;\n      border-radius: 0;\n      background: transparent;\n      box-shadow: none;\n      cursor: pointer;\n    }\n\n    .audio-discussion-button img {\n      display: block;\n      width: 100%;\n      height: auto;\n      object-fit: contain;\n      filter: drop-shadow(0 16px 22px rgba(91, 58, 36, 0.16));\n      transition: transform 180ms ease;\n    }\n\n    .audio-discussion-button:hover img {\n      transform: translateY(-2px);\n    }\n\n    .audio-popup {\n      position: fixed;\n      inset: 0;\n      z-index: 140;\n      display: none;\n      padding: clamp(18px, 3vw, 32px);\n      background: rgba(23, 19, 15, 0.94);\n    }\n\n    .audio-discussion-toggle:checked ~ .audio-popup {\n      display: grid;\n    }\n\n    .audio-popup-scrim {\n      position: absolute;\n      inset: 0;\n      cursor: pointer;\n    }\n\n    .audio-popup-panel {\n      position: relative;\n      z-index: 1;\n      width: min(100%, 980px);\n      min-height: min(72vh, 680px);\n      display: grid;\n      gap: clamp(20px, 4vw, 34px);\n      align-content: center;\n      justify-self: center;\n      align-self: center;\n      border: 1px solid rgba(232, 216, 184, 0.22);\n      border-radius: 8px;\n      padding: clamp(22px, 4vw, 48px);\n      background:\n        linear-gradient(145deg, rgba(247, 243, 232, 0.96), rgba(232, 216, 184, 0.84)),\n        radial-gradient(circle at 50% 0%, rgba(185, 146, 69, 0.18), transparent 42%);\n      box-shadow: 0 28px 70px rgba(0, 0, 0, 0.42);\n    }\n\n    .soundwave {\n      min-height: clamp(150px, 24vw, 240px);\n      display: flex;\n      gap: clamp(7px, 1.3vw, 14px);\n      align-items: center;\n      justify-content: center;\n      padding: clamp(16px, 3vw, 30px);\n    }\n\n    .soundwave span {\n      width: clamp(7px, 1.2vw, 13px);\n      height: 42%;\n      border-radius: 999px;\n      background: linear-gradient(180deg, var(--gold), var(--forest));\n      animation: soundwave-rise 1.05s ease-in-out infinite;\n      box-shadow: 0 10px 20px rgba(91, 58, 36, 0.16);\n    }\n\n    .soundwave span:nth-child(2) {\n      animation-delay: -0.86s;\n    }\n\n    .soundwave span:nth-child(3) {\n      animation-delay: -0.68s;\n    }\n\n    .soundwave span:nth-child(4) {\n      animation-delay: -0.5s;\n    }\n\n    .soundwave span:nth-child(5) {\n      animation-delay: -0.32s;\n    }\n\n    .soundwave span:nth-child(6) {\n      animation-delay: -0.14s;\n    }\n\n    .soundwave span:nth-child(7) {\n      animation-delay: -0.76s;\n    }\n\n    .soundwave span:nth-child(8) {\n      animation-delay: -0.58s;\n    }\n\n    .soundwave span:nth-child(9) {\n      animation-delay: -0.4s;\n    }\n\n    .soundwave span:nth-child(10) {\n      animation-delay: -0.22s;\n    }\n\n    @keyframes soundwave-rise {\n      0%,\n      100% {\n        transform: scaleY(0.34);\n      }\n\n      50% {\n        transform: scaleY(1);\n      }\n    }\n\n    .audio-popup audio {\n      width: min(100%, 760px);\n      justify-self: center;\n      accent-color: var(--forest);\n    }\n\n    .audio-popup-close {\n      min-height: 42px;\n      width: fit-content;\n      display: inline-flex;\n      align-items: center;\n      justify-content: center;\n      justify-self: center;\n      border: 1px solid rgba(35, 70, 56, 0.18);\n      border-radius: 8px;\n      padding: 0 16px;\n      background: var(--forest);\n      color: var(--paper);\n      font-weight: 800;\n      cursor: pointer;\n      transition:\n        background 160ms ease,\n        transform 160ms ease;\n    }\n\n    .audio-popup-close:hover {\n      background: #1d3a2f;\n      transform: translateY(-1px);\n    }\n\n    .wrong-thinking-section {\n      width: min(100%, 1180px);\n      display: grid;\n      gap: clamp(16px, 2.6vw, 24px);\n      margin-inline: auto;\n    }\n\n    .wrong-thinking-section h2 {\n      margin: 0;\n      color: var(--forest);\n      font-size: clamp(1.75rem, 4vw, 2.7rem);\n      line-height: 1.08;\n    }\n\n    .scholars-heading {\n      margin: clamp(6px, 1.4vw, 12px) 0 0;\n      color: var(--deep-kraft);\n      font-size: clamp(1.2rem, 2.4vw, 1.7rem);\n      font-weight: 850;\n      text-align: center;\n    }\n\n    .wrong-thinking-images,\n    .wrong-card-grid {\n      display: grid;\n      grid-template-columns: repeat(2, minmax(0, 1fr));\n      gap: clamp(14px, 2.4vw, 22px);\n      width: 100%;\n    }\n\n    .wrong-thinking-image {\n      border: 1px solid rgba(91, 58, 36, 0.18);\n      border-radius: 8px;\n      padding: clamp(10px, 1.8vw, 18px);\n      background: rgba(255, 255, 255, 0.58);\n      box-shadow: 0 18px 36px rgba(91, 58, 36, 0.14);\n    }\n\n    .wrong-thinking-image:nth-child(1) {\n      background:\n        linear-gradient(145deg, rgba(210, 225, 194, 0.96), rgba(124, 143, 90, 0.34)),\n        radial-gradient(circle at 12% 0%, rgba(35, 70, 56, 0.16), transparent 42%);\n    }\n\n    .wrong-thinking-image:nth-child(2) {\n      background:\n        linear-gradient(145deg, rgba(236, 214, 151, 0.96), rgba(217, 154, 61, 0.28)),\n        radial-gradient(circle at 92% 0%, rgba(91, 58, 36, 0.14), transparent 42%);\n    }\n\n    .wrong-thinking-image {\n      margin: 0;\n      overflow: hidden;\n    }\n\n    .wrong-thinking-image img {\n      display: block;\n      width: 100%;\n      height: 100%;\n      min-height: clamp(280px, 34vw, 430px);\n      object-fit: contain;\n      border-radius: 6px;\n      background: rgba(247, 243, 232, 0.28);\n    }\n\n    .wrong-flip-card {\n      position: relative;\n      aspect-ratio: 4 / 3;\n      min-height: 0;\n    }\n\n    .wrong-flip-toggle,\n    .wrong-slide-toggle {\n      position: absolute;\n      width: 1px;\n      height: 1px;\n      opacity: 0;\n      pointer-events: none;\n    }\n\n    .wrong-flip-cover {\n      position: absolute;\n      inset: 0;\n      overflow: hidden;\n      border-radius: 0;\n      background: transparent;\n      box-shadow: none;\n      cursor: pointer;\n    }\n\n    .wrong-flip-cover img {\n      display: block;\n      width: 100%;\n      height: 100%;\n      object-fit: contain;\n      object-position: center;\n      transition: transform 220ms ease;\n    }\n\n    .wrong-flip-cover:hover img {\n      transform: none;\n    }\n\n    .wrong-flip-cta,\n    .wrong-popup-close,\n    .wrong-carousel-controls label {\n      min-height: 42px;\n      display: inline-flex;\n      align-items: center;\n      justify-content: center;\n      border: 1px solid rgba(35, 70, 56, 0.18);\n      border-radius: 8px;\n      background: var(--forest);\n      color: var(--paper);\n      font-weight: 800;\n      cursor: pointer;\n      transition:\n        background 160ms ease,\n        transform 160ms ease;\n    }\n\n    .wrong-flip-cta {\n      position: absolute;\n      right: clamp(14px, 2vw, 20px);\n      bottom: clamp(14px, 2vw, 20px);\n      padding: 0 18px;\n      background: rgba(35, 70, 56, 0.92);\n      box-shadow: 0 12px 26px rgba(23, 19, 15, 0.2);\n    }\n\n    .wrong-flip-cta:hover,\n    .wrong-popup-close:hover,\n    .wrong-carousel-controls label:hover {\n      background: #1d3a2f;\n      transform: translateY(-1px);\n    }\n\n    .wrong-carousel-popup {\n      position: fixed;\n      inset: 0;\n      z-index: 120;\n      display: none;\n      padding: clamp(12px, 2vw, 24px);\n      background: rgba(23, 19, 15, 0.94);\n    }\n\n    .wrong-flip-toggle:checked ~ .wrong-carousel-popup {\n      display: grid;\n    }\n\n    .wrong-popup-scrim {\n      position: absolute;\n      inset: 0;\n      cursor: pointer;\n    }\n\n    .wrong-popup-panel {\n      position: relative;\n      z-index: 1;\n      min-width: 0;\n      min-height: 0;\n      display: grid;\n      border-radius: 8px;\n      overflow: hidden;\n      background: rgba(247, 243, 232, 0.08);\n    }\n\n    .wrong-carousel {\n      position: relative;\n      min-height: 0;\n      display: grid;\n      grid-template-rows: minmax(0, 1fr) auto;\n      gap: 12px;\n    }\n\n    .wrong-carousel-window {\n      min-height: 0;\n      overflow: hidden;\n      border: 0;\n      border-radius: 8px;\n      background: rgba(247, 243, 232, 0.08);\n    }\n\n    .wrong-carousel-track {\n      display: flex;\n      width: 200%;\n      height: 100%;\n      transition: transform 320ms ease;\n    }\n\n    .wrong-carousel-slide {\n      flex: 0 0 50%;\n      margin: 0;\n    }\n\n    .wrong-carousel-slide img {\n      display: block;\n      width: 100%;\n      height: 100%;\n      object-fit: contain;\n      padding: 0;\n    }\n\n    .wrong-slide-two-toggle:checked ~ .wrong-carousel-window .wrong-carousel-track {\n      transform: translateX(-50%);\n    }\n\n    .wrong-carousel-controls {\n      display: grid;\n      grid-template-columns: minmax(52px, 0.12fr) minmax(52px, 0.12fr) auto;\n      gap: 10px;\n      align-items: center;\n      justify-content: center;\n    }\n\n    .wrong-carousel-controls label {\n      min-width: 42px;\n      padding: 0 12px;\n      background: rgba(35, 70, 56, 0.82);\n      font-size: 0.9