lid rgba(185, 146, 69, 0.72);\n      border-radius: 8px;\n      padding: clamp(12px, 1.8vw, 16px) clamp(14px, 2vw, 18px);\n      background:\n        linear-gradient(145deg, rgba(255, 255, 255, 0.46), rgba(247, 243, 232, 0.7)),\n        radial-gradient(circle at 100% 0%, rgba(185, 146, 69, 0.1), transparent 34%);\n      box-shadow: 0 12px 26px rgba(91, 58, 36, 0.08);\n    }\n\n    .teaching-section.everyday-life-section {\n      border-left-color: rgba(79, 107, 58, 0.86);\n      background:\n        linear-gradient(145deg, rgba(124, 143, 90, 0.14), rgba(247, 243, 232, 0.76)),\n        radial-gradient(circle at 100% 0%, rgba(79, 107, 58, 0.12), transparent 34%);\n    }\n\n    .teaching-section.misunderstanding-section {\n      border-color: rgba(217, 154, 61, 0.34);\n      border-left-color: var(--amber);\n      background:\n        linear-gradient(145deg, rgba(217, 154, 61, 0.2), rgba(247, 243, 232, 0.78)),\n        radial-gradient(circle at 100% 0%, rgba(154, 107, 63, 0.14), transparent 34%);\n    }\n\n    .teaching-section.misunderstanding-section h3 {\n      color: var(--deep-kraft);\n    }\n\n    .teaching-section.takeaway-section {\n      border-left-color: rgba(35, 70, 56, 0.84);\n      background:\n        linear-gradient(145deg, rgba(35, 70, 56, 0.1), rgba(247, 243, 232, 0.76)),\n        radial-gradient(circle at 100% 0%, rgba(185, 146, 69, 0.12), transparent 34%);\n    }\n\n    .teaching-section:first-of-type {\n      margin-top: 0;\n    }\n\n    .teaching-section h3,\n    .teaching-section p {\n      margin: 0;\n    }\n\n    .teaching-section h3 {\n      margin-bottom: 10px;\n      color: var(--forest);\n      font-size: clamp(1.05rem, 2vw, 1.22rem);\n      line-height: 1.2;\n    }\n\n    .teaching-section p + p {\n      margin-top: 22px;\n    }\n\n    .teaching-section p,\n    .economics-list li {\n      color: var(--deep-kraft);\n      font-size: clamp(0.96rem, 1.55vw, 1.08rem);\n      line-height: 1.72;\n    }\n\n    .economics-list {\n      grid-template-columns: repeat(auto-fit, minmax(210px, 1fr));\n      gap: 8px 18px;\n      margin: 9px 0 0;\n      padding-left: 18px;\n    }\n\n    .economics-visual-card {\n      clear: both;\n      margin: clamp(18px, 3vw, 26px) 0;\n      border: 1px solid rgba(91, 58, 36, 0.16);\n      border-radius: 8px;\n      padding: clamp(10px, 1.8vw, 14px);\n      background:\n        linear-gradient(145deg, rgba(247, 243, 232, 0.86), rgba(255, 255, 255, 0.58)),\n        radial-gradient(circle at 12% 0%, rgba(217, 154, 61, 0.12), transparent 32%);\n      box-shadow: 0 16px 34px rgba(91, 58, 36, 0.12);\n    }\n\n    .economics-visual-card img {\n      display: block;\n      width: 100%;\n      max-height: 520px;\n      object-fit: contain;\n      border-radius: 6px;\n    }\n\n    .quote-card-row,\n    .concept-card-row {\n      display: grid;\n      grid-template-columns: repeat(2, minmax(0, 1fr));\n      gap: clamp(14px, 2.5vw, 20px);\n    }\n\n    .quote-card-row {\n      align-items: stretch;\n    }\n\n    .quote-card {\n      display: grid;\n      place-items: center;\n      border: 1px solid rgba(185, 146, 69, 0.34);\n      border-left: 5px solid var(--gold);\n      border-radius: 8px;\n      padding: 12px;\n      background: rgba(247, 243, 232, 0.74);\n      box-shadow: 0 16px 34px rgba(91, 58, 36, 0.12);\n    }\n\n    .quote-card img {\n      width: 100%;\n      max-height: 210px;\n      object-fit: contain;\n      mix-blend-mode: multiply;\n      filter: drop-shadow(0 10px 12px rgba(91, 58, 36, 0.12));\n    }\n\n    .concept-card-row {\n      grid-template-columns: repeat(3, minmax(0, 1fr));\n    }\n\n    .concept-card {\n      border: 1px solid rgba(91, 58, 36, 0.15);\n      border-radius: 8px;\n      padding: 16px;\n      background: rgba(255, 255, 255, 0.5);\n      box-shadow: 0 14px 28px rgba(91, 58, 36, 0.1);\n    }\n\n    .concept-card strong {\n      display: block;\n      margin-bottom: 7px;\n      color: var(--gold);\n      font-size: 0.76rem;\n      text-transform: uppercase;\n    }\n\n    .concept-card h3,\n    .concept-card p {\n      margin: 0;\n    }\n\n    .concept-card h3 {\n      margin-bottom: 7px;\n      color: var(--forest);\n      font-size: 1.04rem;\n    }\n\n    .concept-card p {\n      color: var(--muted);\n      line-height: 1.5;\n    }\n\n    .economics-highlight {\n      border: 1px solid rgba(185, 146, 69, 0.36);\n      border-left: 5px solid var(--gold);\n      border-radius: 8px;\n      padding: 16px 18px;\n      background: rgba(217, 154, 61, 0.1);\n      box-shadow: 0 14px 28px rgba(91, 58, 36, 0.1);\n    }\n\n    .economics-highlight h3,\n    .economics-highlight p {\n      margin: 0;\n    }\n\n    .economics-highlight h3 {\n      margin-bottom: 7px;\n      color: var(--forest);\n    }\n\n    .economics-choice-chart {\n      display: grid;\n      gap: 12px;\n      border: 1px solid rgba(91, 58, 36, 0.15);\n      border-radius: 8px;\n      padding: 16px;\n      background: rgba(255, 255, 255, 0.48);\n      box-shadow: 0 14px 28px rgba(91, 58, 36, 0.1);\n    }\n\n    .economics-choice-chart h3 {\n      margin: 0;\n      color: var(--forest);\n    }\n\n    .choice-chart-row {\n      display: grid;\n      grid-template-columns: minmax(90px, 0.18fr) minmax(0, 1fr);\n      gap: 12px;\n      align-items: center;\n    }\n\n    .choice-chart-row strong {\n      color: var(--deep-kraft);\n    }\n\n    .choice-chart-tags {\n      display: flex;\n      gap: 8px;\n      flex-wrap: wrap;\n    }\n\n    .choice-chart-tags span {\n      border: 1px solid rgba(79, 107, 58, 0.2);\n      border-radius: 999px;\n      padding: 6px 10px;\n      background: rgba(124, 143, 90, 0.17);\n      color: var(--forest);\n      font-size: 0.86rem;\n      font-weight: 750;\n    }\n\n    .faith-reflection {\n      border-color: rgba(217, 154, 61, 0.44);\n      border-left-color: var(--amber);\n      background:\n        linear-gradient(145deg, rgba(217, 154, 61, 0.13), rgba(247, 243, 232, 0.74));\n    }\n\n    .pillars-page {\n      display: grid;\n      gap: clamp(18px, 3vw, 28px);\n    }\n\n    .pillars-hero {\n      display: grid;\n      gap: 10px;\n      justify-items: center;\n      text-align: center;\n      padding: clamp(18px, 3vw, 28px);\n      border: 1px solid rgba(91, 58, 36, 0.18);\n      border-radius: 8px;\n      background:\n        linear-gradient(145deg, rgba(247, 243, 232, 0.94), rgba(232, 216, 184, 0.7)),\n        radial-gradient(circle at 50% 0%, rgba(217, 154, 61, 0.16), transparent 36%);\n      box-shadow: 0 18px 42px rgba(91, 58, 36, 0.14);\n    }\n\n    .pillars-hero h2 {\n      max-width: 980px;\n      margin: 0;\n      font-family: Georgia, \"Times New Roman\", serif;\n      color: var(--forest);\n      font-size: clamp(2rem, 6vw, 4.4rem);\n      line-height: 1;\n    }\n\n    .pillars-hero p {\n      max-width: 760px;\n      margin: 0;\n      color: var(--deep-kraft);\n      font-size: clamp(0.98rem, 1.5vw, 1.12rem);\n    }\n\n    .pillars-grid {\n      position: relative;\n      display: grid;\n      grid-template-columns: repeat(2, minmax(260px, 1fr));\n      gap: clamp(16px, 2.5vw, 26px);\n      padding: clamp(12px, 2vw, 18px);\n      border-radius: 8px;\n      overflow: visible;\n      background:\n        linear-gradient(180deg, rgba(247, 243, 232, 0.42), rgba(232, 216, 184, 0.36)),\n        radial-gradient(circle at 0% 100%, rgba(185, 146, 69, 0.12), transparent 30%);\n    }\n\n    .pillar-card-shell {\n      position: relative;\n      min-height: clamp(210px, 22vw, 280px);\n      z-index: 0;\n    }\n\n    .pillar-card-shell:has(.pillar-toggle:checked) {\n      z-index: 1000;\n    }\n\n    .pillar-toggle {\n      position: absolute;\n      width: 1px;\n      height: 1px;\n      opacity: 0;\n      pointer-events: none;\n    }\n\n    .pillar-flip-card {\n      position: relative;\n      display: block;\n      width: 100%;\n      height: 100%;\n      min-height: inherit;\n      cursor: pointer;\n      transform-style: preserve-3d;\n      transition:\n        transform 420ms ease,\n        filter 180ms ease;\n    }\n\n    .pillar-toggle:checked + .pillar-flip-card {\n      z-index: 4;\n      transform: translateY(-2px) scale(1.01);\n      filter: drop-shadow(0 24px 30px rgba(91, 58, 36, 0.18));\n    }\n\n    .pillar-toggle:focus-visible + .pillar-flip-card .pillar-face {\n      outline: 3px solid rgba(185, 146, 69, 0.45);\n      outline-offset: 3px;\n    }\n\n    .pillar-face {\n      position: absolute;\n      inset: 0;\n      overflow: hidden;\n      border: 2px solid rgba(185, 146, 69, 0.58);\n      border-radius: 8px;\n      backface-visibility: hidden;\n      box-shadow:\n        0 18px 34px rgba(91, 58, 36, 0.13),\n        inset 0 1px 0 rgba(255, 255, 255, 0.7);\n    }\n\n    .pillar-front {\n      display: grid;\n      grid-template-columns: minmax(112px, 0.42fr) minmax(0, 1fr);\n      gap: clamp(14px, 2vw, 22px);\n      align-items: center;\n      padding: clamp(22px, 3vw, 32px);\n      background:\n        linear-gradient(145deg, rgba(247, 243, 232, 0.96), rgba(232, 216, 184, 0.56)),\n        radial-gradient(circle at 0% 100%, rgba(185, 146, 69, 0.18), transparent 34%);\n    }\n\n    .pillar-icon {\n      display: grid;\n      place-items: center;\n      min-height: 128px;\n      color: var(--gold);\n    }\n\n    .pillar-icon img {\n      display: block;\n      width: min(150px, 100%);\n      height: auto;\n      max-height: 150px;\n      object-fit: contain;\n      filter: drop-shadow(0 10px 10px rgba(91, 58, 36, 0.16));\n    }\n\n    .pillar-front h3,\n    .pillar-front p,\n    .pillar-popup-card h3,\n    .pillar-popup-card p {\n      margin: 0;\n    }\n\n    .pillar-front h3 {\n      color: var(--forest);\n      font-family: Georgia, \"Times New Roman\", serif;\n      font-size: clamp(1.75rem, 3.5vw, 3.15rem);\n      line-height: 1;\n    }\n\n    .pillar-front p {\n      max-width: 30rem;\n      margin-top: 10px;\n      color: var(--deep-kraft);\n      font-size: clamp(0.95rem, 1.35vw, 1.08rem);\n      line-height: 1.35;\n    }\n\n    .pillar-front span {\n      display: inline-flex;\n      width: fit-content;\n      margin-top: 14px;\n      border-radius: 999px;\n      padding: 6px 10px;\n      background: rgba(185, 146, 69, 0.16);\n      color: var(--deep-kraft);\n      font-size: 0.78rem;\n      font-weight: 800;\n      text-transform: uppercase;\n    }\n\n    .pillar-popup {\n      position: fixed;\n      inset: 0;\n      z-index: 9999;\n      isolation: isolate;\n      display: grid;\n      place-items: center;\n      padding: clamp(16px, 4vw, 38px);\n      background: rgba(23, 19, 15, 0.68);\n      backdrop-filter: blur(5px);\n      opacity: 0;\n      pointer-events: none;\n      visibility: hidden;\n      transition:\n        opacity 180ms ease,\n        visibility 180ms ease;\n    }\n\n    .pillar-toggle:checked ~ .pillar-popup {\n      opacity: 1;\n      pointer-events: auto;\n      visibility: visible;\n    }\n\n    .pillar-popup-backdrop {\n      position: absolute;\n      inset: 0;\n      cursor: pointer;\n    }\n\n    .pillar-popup-card {\n      position: relative;\n      z-index: 1;\n      width: min(760px, calc(100vw - 28px));\n      max-height: min(84vh, 680px);\n      display: grid;\n      gap: clamp(14px, 2vw, 18px);\n      overflow: auto;\n      border: 2px solid rgba(185, 146, 69, 0.58);\n      border-radius: 8px;\n      padding: clamp(20px, 3vw, 32px);\n      background:\n        linear-gradient(145deg, #f7f3e8, #f0e5cf),\n        radial-gradient(circle at 100% 0%, rgba(79, 107, 58, 0.12), transparent 36%);\n      box-shadow: 0 34px 90px rgba(23, 19, 15, 0.52);\n      transform: translateY(18px) rotateX(4deg) scale(0.97);\n      transform-origin: center;\n      transition: transform 220ms ease;\n    }\n\n    .pillar-toggle:checked ~ .pillar-popup .pillar-popup-card {\n      transform: translateY(0) rotateX(0) scale(1);\n    }\n\n    .pillar-popup-close {\n      position: sticky;\n      top: 0;\n      justify-self: end;\n      border: 1px solid rgba(91, 58, 36, 0.2);\n      border-radius: 999px;\n      padding: 7px 12px;\n      background: #f7f3e8;\n      color: var(--deep-kraft);\n      cursor: pointer;\n      font-size: 0.78rem;\n      font-weight: 850;\n      text-transform: uppercase;\n      box-shadow: 0 8px 16px rgba(91, 58, 36, 0.12);\n    }\n\n    .pillar-popup-card strong {\n      color: var(--gold);\n      font-size: 0.76rem;\n      text-transform: uppercase;\n    }\n\n    .pillar-popup-card h3 {\n      color: var(--forest);\n      max-width: 100%;\n      font-size: clamp(1.55rem, 3vw, 2.25rem);\n      line-height: 1.16;\n      text-wrap: balance;\n    }\n\n    .pillar-popup-card p {\n      color: var(--muted);\n      max-width: 68ch;\n      font-size: clamp(1.04rem, 1.55vw, 1.18rem);\n      line-height: 1.65;\n    }\n\n    .complete-button {\n      display: inline-flex;\n      min-height: 42px;\n      align-items: center;\n      justify-content: center;\n      margin-top: 22px;\n      padding: 0 16px;\n      border: 1px solid var(--forest);\n      border-radius: 8px;\n      background: linear-gradient(145deg, var(--forest), var(--ubuntu));\n      color: var(--paper);\n      font: inherit;\n      font-weight: 750;\n      cursor: pointer;\n      box-shadow: 0 12px 24px rgba(35, 70, 56, 0.22);\n      transition:\n        background 160ms ease,\n        transform 160ms ease,\n        box-shadow 160ms ease;\n    }\n\n    .complete-button:hover {\n      background: linear-gradient(145deg, #1d3a2f, var(--forest));\n      box-shadow: 0 14px 28px rgba(35, 70, 56, 0.26);\n      transform: translateY(-1px);\n    }\n\n    @media (max-width: 640px) {\n      .comparison {\n        grid-template-columns: 1fr;\n      }\n\n      .comparison div:first-child {\n        border-right: 0;\n        border-bottom: 1px solid rgba(91, 58, 36, 0.18);\n      }\n\n      .value-row {\n        grid-template-columns: 1fr;\n        gap: 6px;\n      }\n\n      .ordinary-hero {\n        float: none;\n        width: 100%;\n        margin: 0 0 18px;\n      }\n\n      .ordinary-copy p {\n        font-size: 1rem;\n        line-height: 1.56;\n      }\n\n      .market-theology-visual {\n        float: none;\n        width: 100%;\n        margin: 0 0 18px;\n      }\n\n      .audio-discussion-button {\n        width: min(100%, 360px);\n      }\n\n      .audio-popup-panel {\n        min-height: min(72vh, 560px);\n        padding: 18px;\n      }\n\n      .soundwave {\n        min-height: 130px;\n      }\n\n      .wrong-thinking-images,\n      .wrong-card-grid {\n        grid-template-columns: 1fr;\n      }\n\n      .wrong-thinking-image img {\n        min-height: 0;\n      }\n\n      .wrong-flip-card {\n        min-height: 0;\n      }\n\n      .market-image-story p {\n        font-size: 1rem;\n        line-height: 1.58;\n      }\n\n      .transparent-quote-row {\n        grid-template-columns: 1fr;\n      }\n\n      .economics-step-header {\n        align-items: flex-start;\n      }\n\n      .economics-hero-layout {\n        grid-template-columns: 1fr;\n      }\n\n      .economics-square-image {\n        height: auto;\n        min-height: 0;\n        object-fit: contain;\n      }\n\n      .quote-card-row,\n      .concept-card-row {\n        grid-template-columns: 1fr;\n      }\n\n      .pillars-grid {\n        grid-template-columns: 1fr;\n      }\n\n      .pillar-card-shell {\n        min-height: 250px;\n      }\n\n      .pillar-front {\n        grid-template-columns: 1fr;\n        justify-items: center;\n        text-align: center;\n      }\n\n      .choice-chart-row {\n        grid-template-columns: 1fr;\n        gap: 7px;\n      }\n    }\n  </style>\n  <main class=\"rich-step\" data-rich-lesson-step>\n    \n      <section class=\"economics-step-page\">\n        <header class=\"economics-step-header\">\n          <div>\n            <p class=\"eyebrow\">Step 3</p>\n            <h2>Understanding Economics in Everyday Life</h2>\n          </div>\n          <div class=\"completion-icon\" aria-label=\"Step status\">&#10003;</div>\n        </header>\n\n        <section class=\"economics-teaching-panel\">\n          <p class=\"eyebrow\">The study of choices</p>\n          <h2>What Is Economics?</h2>\n          <div class=\"economics-hero-layout\">\n            <img\n              class=\"economics-square-image\"\n              src=\"https://static.wixstatic.com/media/7638b6_f52c1f6f2d0c42a980e209c87b9db1dd~mv2.png\"\n              alt=\"Papercraft public building representing shared economic choices\"\n            />\n            <div class=\"economics-hero-copy\">\n              <section class=\"teaching-section\">\n                <h3>What Economics Means</h3>\n                <p>\n                  Economics is the study of the choices persons, businesses, and governments make when they use limited\n                  means to satisfy unlimited wants and essential needs. We all want many things, but we are limited in\n                  how we can meet those wants and needs. Because we do not have unlimited time, money, energy, skills,\n                  or materials, we must make choices.\n                </p>\n              </section>\n\n              <section class=\"teaching-section\">\n                <h3>Why Choices Matter</h3>\n                <p>\n                  Life is full of constraints. We cannot do everything, buy everything, or produce everything at once.\n                  Economics helps us understand how people decide what matters most and how they make the best use of\n                  what they have. Economics is the science of figuring out how to make the most of what we have got.\n                </p>\n              </section>\n            </div>\n          </div>\n\n          <figure class=\"economics-visual-card\">\n            <img\n              src=\"https://static.wixstatic.com/media/7638b6_4acddffa7162437eb2b046ff7ceeb9c3~mv2.png\"\n              alt=\"Visual explanation of the everyday areas economics looks at\"\n            />\n          </figure>\n\n          <section class=\"teaching-section everyday-life-section\">\n            <h3>Economics in Everyday Life</h3>\n            <p>\n              The scope of economic activity reaches into everyday life. It helps us understand how individuals and\n              society interact in the interest of well-being, while trying to meet essential needs and important wants.\n              Economics also considers the choices and trade-offs people make as they try to use resources wisely and\n              achieve better outcomes.\n            </p>\n          </section>\n\n          <section class=\"teaching-section misunderstanding-section\">\n            <h3>Common Misunderstanding</h3>\n            <p>\n              Many people misunderstand economics as only being about complex mathematical models, the stock exchange,\n              government policy, or making money. However, economics goes far beyond that. It is about the resources we\n              have, how we use them, our connections with people, organisations, and nations, what we do to create or\n              obtain resources, and how we use and share them.\n            </p>\n          </section>\n\n          <section class=\"teaching-section takeaway-section\">\n            <h3>Final Takeaway</h3>\n            <p>\n              Economics is not only about numbers. It is about choices, limited resources, human needs, and how people\n              live together.\n            </p>\n          </section>\n        </section>\n\n        <div class=\"quote-card-row\" aria-label=\"Economics quote visuals\">\n          <figure class=\"quote-card\">\n            <img src=\"https://static.wixstatic.com/media/7638b6_cf834dcfb79f4803a64eb0cc7b0de17b~mv2.png\" alt=\"Alfred Marshall quote about economics and ordinary life\" />\n          </figure>\n          <figure class=\"quote-card\">\n            <img src=\"https://static.wixstatic.com/media/7638b6_bda9733d617c4cca965c4c45b6971001~mv2.png\" alt=\"Gary Becker quote about economy and making the most of life\" />\n          </figure>\n        </div>\n\n      </section>\n    \n    <button class=\"complete-button\" data-classroom-complete data-score=\"5\" data-max-score=\"5\">Continue</button>\n  </main>\n"},{"id":"level-1-session-1-the-daily-grind-practical-economic-elements","kind":"customHtml","title":"Step 4: Practical Economic Elements","body":"\n  <style>\n    :root {\n      color-scheme: light;\n      --paper: #f7f3e8;\n      --cream: #e8d8b8;\n      --forest: #234638;\n      --ubuntu: #4f6b3a;\n      --leaf: #7c8f5a;\n      --gold: #b99245;\n      --amber: #d99a3d;\n      --kraft: #9a6b3f;\n      --deep-kraft: #5b3a24;\n      --ink: #17130f;\n      --muted: #5d6659;\n    }\n\n    * {\n      box-sizing: border-box;\n    }\n\n    body {\n      margin: 0;\n      font-family: \"Segoe UI\", system-ui, sans-serif;\n      background:\n        linear-gradient(180deg, rgba(247, 243, 232, 0.98), rgba(232, 216, 184, 0.74)),\n        radial-gradient(circle at 16% 10%, rgba(217, 154, 61, 0.16), transparent 32%);\n      color: var(--ink);\n    }\n\n    .rich-step {\n      min-height: 100vh;\n      padding: clamp(18px, 4vw, 34px);\n    }\n\n    h2,\n    h3,\n    p {\n      margin-top: 0;\n    }\n\n    h2 {\n      margin-bottom: 10px;\n      color: var(--forest);\n      font-size: clamp(1.65rem, 4vw, 2.6rem);\n      line-height: 1.08;\n    }\n\n    h3 {\n      margin-bottom: 8px;\n      color: var(--forest);\n      font-size: 1.08rem;\n    }\n\n    p {\n      color: var(--muted);\n      line-height: 1.62;\n    }\n\n    .intro {\n      width: 100%;\n      max-width: none;\n      margin-bottom: 22px;\n      font-size: 1rem;\n    }\n\n    .eyebrow {\n      margin-bottom: 8px;\n      color: var(--gold);\n      font-size: 0.78rem;\n      font-weight: 800;\n      letter-spacing: 0;\n      text-transform: uppercase;\n    }\n\n    .grid {\n      display: grid;\n      grid-template-columns: repeat(auto-fit, minmax(220px, 1fr));\n      gap: 14px;\n      margin: 18px 0;\n    }\n\n    .card,\n    .callout,\n    .comparison {\n      border: 1px solid rgba(91, 58, 36, 0.18);\n      border-radius: 8px;\n      background: rgba(255, 255, 255, 0.56);\n      box-shadow: 0 16px 34px rgba(91, 58, 36, 0.12);\n    }\n\n    .card {\n      padding: 16px;\n    }\n\n    .card strong {\n      display: block;\n      margin-bottom: 6px;\n      color: var(--deep-kraft);\n      font-size: 0.86rem;\n      text-transform: uppercase;\n    }\n\n    .pill {\n      display: inline-flex;\n      min-height: 28px;\n      align-items: center;\n      margin: 8px 6px 0 0;\n      padding: 0 10px;\n      border-radius: 999px;\n      background: rgba(124, 143, 90, 0.22);\n      color: var(--forest);\n      font-size: 0.82rem;\n      font-weight: 750;\n    }\n\n    .callout {\n      margin-top: 18px;\n      padding: 16px;\n      border-left: 5px solid var(--gold);\n      background: rgba(217, 154, 61, 0.1);\n    }\n\n    .comparison {\n      display: grid;\n      grid-template-columns: minmax(0, 1fr) minmax(0, 1fr);\n      overflow: hidden;\n    }\n\n    .comparison div {\n      padding: 14px;\n    }\n\n    .comparison div:first-child {\n      border-right: 1px solid rgba(91, 58, 36, 0.18);\n      background: rgba(35, 70, 56, 0.08);\n    }\n\n    ul {\n      display: grid;\n      gap: 9px;\n      margin: 10px 0 0;\n      padding-left: 18px;\n      color: var(--muted);\n      line-height: 1.5;\n    }\n\n    textarea {\n      width: 100%;\n      min-height: 150px;\n      margin-top: 12px;\n      border: 1px solid rgba(91, 58, 36, 0.22);\n      border-radius: 8px;\n      padding: 12px 14px;\n      background: rgba(255, 255, 255, 0.72);\n      color: var(--ink);\n      font: inherit;\n      line-height: 1.55;\n      resize: vertical;\n      box-shadow: inset 0 1px 0 rgba(255, 255, 255, 0.72);\n    }\n\n    textarea:focus {\n      outline: 3px solid rgba(185, 146, 69, 0.28);\n      outline-offset: 2px;\n    }\n\n    .market-theology-page {\n      display: grid;\n      gap: clamp(18px, 3vw, 26px);\n      align-items: stretch;\n      justify-items: center;\n    }\n\n    .audio-discussion {\n      width: min(100%, 1180px);\n      display: grid;\n      gap: 10px;\n      justify-items: center;\n      margin-inline: auto;\n    }\n\n    .audio-discussion-copy {\n      margin: 0;\n      color: var(--forest);\n      font-size: clamp(1rem, 1.6vw, 1.18rem);\n      font-weight: 800;\n      text-align: center;\n    }\n\n    .audio-discussion-toggle {\n      position: absolute;\n      width: 1px;\n      height: 1px;\n      opacity: 0;\n      pointer-events: none;\n    }\n\n    .audio-discussion-button {\n      width: min(100%, 480px);\n      display: block;\n      padding: 0;\n      border: 0;\n      border-radius: 0;\n      background: transparent;\n      box-shadow: none;\n      cursor: pointer;\n    }\n\n    .audio-discussion-button img {\n      display: block;\n      width: 100%;\n      height: auto;\n      object-fit: contain;\n      filter: drop-shadow(0 16px 22px rgba(91, 58, 36, 0.16));\n      transition: transform 180ms ease;\n    }\n\n    .audio-discussion-button:hover img {\n      transform: translateY(-2px);\n    }\n\n    .audio-popup {\n      position: fixed;\n      inset: 0;\n      z-index: 140;\n      display: none;\n      padding: clamp(18px, 3vw, 32px);\n      background: rgba(23, 19, 15, 0.94);\n    }\n\n    .audio-discussion-toggle:checked ~ .audio-popup {\n      display: grid;\n    }\n\n    .audio-popup-scrim {\n      position: absolute;\n      inset: 0;\n      cursor: pointer;\n    }\n\n    .audio-popup-panel {\n      position: relative;\n      z-index: 1;\n      width: min(100%, 980px);\n      min-height: min(72vh, 680px);\n      display: grid;\n      gap: clamp(20px, 4vw, 34px);\n      align-content: center;\n      justify-self: center;\n      align-self: center;\n      border: 1px solid rgba(232, 216, 184, 0.22);\n      border-radius: 8px;\n      padding: clamp(22px, 4vw, 48px);\n      background:\n        linear-gradient(145deg, rgba(247, 243, 232, 0.96), rgba(232, 216, 184, 0.84)),\n        radial-gradient(circle at 50% 0%, rgba(185, 146, 69, 0.18), transparent 42%);\n      box-shadow: 0 28px 70px rgba(0, 0, 0, 0.42);\n    }\n\n    .soundwave {\n      min-height: clamp(150px, 24vw, 240px);\n      display: flex;\n      gap: clamp(7px, 1.3vw, 14px);\n      align-items: center;\n      justify-content: center;\n      padding: clamp(16px, 3vw, 30px);\n    }\n\n    .soundwave span {\n      width: clamp(7px, 1.2vw, 13px);\n      height: 42%;\n      border-radius: 999px;\n      background: linear-gradient(180deg, var(--gold), var(--forest));\n      animation: soundwave-rise 1.05s ease-in-out infinite;\n      box-shadow: 0 10px 20px rgba(91, 58, 36, 0.16);\n    }\n\n    .soundwave span:nth-child(2) {\n      animation-delay: -0.86s;\n    }\n\n    .soundwave span:nth-child(3) {\n      animation-delay: -0.68s;\n    }\n\n    .soundwave span:nth-child(4) {\n      animation-delay: -0.5s;\n    }\n\n    .soundwave span:nth-child(5) {\n      animation-delay: -0.32s;\n    }\n\n    .soundwave span:nth-child(6) {\n      animation-delay: -0.14s;\n    }\n\n    .soundwave span:nth-child(7) {\n      animation-delay: -0.76s;\n    }\n\n    .soundwave span:nth-child(8) {\n      animation-delay: -0.58s;\n    }\n\n    .soundwave span:nth-child(9) {\n      animation-delay: -0.4s;\n    }\n\n    .soundwave span:nth-child(10) {\n      animation-delay: -0.22s;\n    }\n\n    @keyframes soundwave-rise {\n      0%,\n      100% {\n        transform: scaleY(0.34);\n      }\n\n      50% {\n        transform: scaleY(1);\n      }\n    }\n\n    .audio-popup audio {\n      width: min(100%, 760px);\n      justify-self: center;\n      accent-color: var(--forest);\n    }\n\n    .audio-popup-close {\n      min-height: 42px;\n      width: fit-content;\n      display: inline-flex;\n      align-items: center;\n      justify-content: center;\n      justify-self: center;\n      border: 1px solid rgba(35, 70, 56, 0.18);\n      border-radius: 8px;\n      padding: 0 16px;\n      background: var(--forest);\n      color: var(--paper);\n      font-weight: 800;\n      cursor: pointer;\n      transition:\n        background 160ms ease,\n        transform 160ms ease;\n    }\n\n    .audio-popup-close:hover {\n      background: #1d3a2f;\n      transform: translateY(-1px);\n    }\n\n    .wrong-thinking-section {\n      width: min(100%, 1180px);\n      display: grid;\n      gap: clamp(16px, 2.6vw, 24px);\n      margin-inline: auto;\n    }\n\n    .wrong-thinking-section h2 {\n      margin: 0;\n      color: var(--forest);\n      font-size: clamp(1.75rem, 4vw, 2.7rem);\n      line-height: 1.08;\n    }\n\n    .scholars-heading {\n      margin: clamp(6px, 1.4vw, 12px) 0 0;\n      color: var(--deep-kraft);\n      font-size: clamp(1.2rem, 2.4vw, 1.7rem);\n      font-weight: 850;\n      text-align: center;\n    }\n\n    .wrong-thinking-images,\n    .wrong-card-grid {\n      display: grid;\n      grid-template-columns: repeat(2, minmax(0, 1fr));\n      gap: clamp(14px, 2.4vw, 22px);\n      width: 100%;\n    }\n\n    .wrong-thinking-image {\n      border: 1px solid rgba(91, 58, 36, 0.18);\n      border-radius: 8px;\n      padding: clamp(10px, 1.8vw, 18px);\n      background: rgba(255, 255, 255, 0.58);\n      box-shadow: 0 18px 36px rgba(91, 58, 36, 0.14);\n    }\n\n    .wrong-thinking-image:nth-child(1) {\n      background:\n        linear-gradient(145deg, rgba(210, 225, 194, 0.96), rgba(124, 143, 90, 0.34)),\n        radial-gradient(circle at 12% 0%, rgba(35, 70, 56, 0.16), transparent 42%);\n    }\n\n    .wrong-thinking-image:nth-child(2) {\n      background:\n        linear-gradient(145deg, rgba(236, 214, 151, 0.96), rgba(217, 154, 61, 0.28)),\n        radial-gradient(circle at 92% 0%, rgba(91, 58, 36, 0.14), transparent 42%);\n    }\n\n    .wrong-thinking-image {\n      margin: 0;\n      overflow: hidden;\n    }\n\n    .wrong-thinking-image img {\n      display: block;\n      width: 100%;\n      height: 100%;\n      min-height: clamp(280px, 34vw, 430px);\n      object-fit: contain;\n      border-radius: 6px;\n      background: rgba(247, 243, 232, 0.28);\n    }\n\n    .wrong-flip-card {\n      position: relative;\n      aspect-ratio: 4 / 3;\n      min-height: 0;\n    }\n\n    .wrong-flip-toggle,\n    .wrong-slide-toggle {\n      position: absolute;\n      width: 1px;\n      height: 1px;\n      opacity: 0;\n      pointer-events: none;\n    }\n\n    .wrong-flip-cover {\n      position: absolute;\n      inset: 0;\n      overflow: hidden;\n      border-radius: 0;\n      background: transparent;\n      box-shadow: none;\n      cursor: pointer;\n    }\n\n    .wrong-flip-cover img {\n      display: block;\n      width: 100%;\n      height: 100%;\n      object-fit: contain;\n      object-position: center;\n      transition: transform 220ms ease;\n    }\n\n    .wrong-flip-cover:hover img {\n      transform: none;\n    }\n\n    .wrong-flip-cta,\n    .wrong-popup-close,\n    .wrong-carousel-controls label {\n      min-height: 42px;\n      display: inline-flex;\n      align-items: center;\n      justify-content: center;\n      border: 1px solid rgba(35, 70, 56, 0.18);\n      border-radius: 8px;\n      background: var(--forest);\n      color: var(--paper);\n      font-weight: 800;\n      cursor: pointer;\n      transition:\n        background 160ms ease,\n        transform 160ms ease;\n    }\n\n    .wrong-flip-cta {\n      position: absolute;\n      right: clamp(14px, 2vw, 20px);\n      bottom: clamp(14px, 2vw, 20px);\n      padding: 0 18px;\n      background: rgba(35, 70, 56, 0.92);\n      box-shadow: 0 12px 26px rgba(23, 19, 15, 0.2);\n    }\n\n    .wrong-flip-cta:hover,\n    .wrong-popup-close:hover,\n    .wrong-carousel-controls label:hover {\n      background: #1d3a2f;\n      transform: translateY(-1px);\n    }\n\n    .wrong-carousel-popup {\n      position: fixed;\n      inset: 0;\n      z-index: 120;\n      display: none;\n      padding: clamp(12px, 2vw, 24px);\n      background: rgba(23, 19, 15, 0.94);\n    }\n\n    .wrong-flip-toggle:checked ~ .wrong-carousel-popup {\n      display: grid;\n    }\n\n    .wrong-popup-scrim {\n      position: absolute;\n      inset: 0;\n      cursor: pointer;\n    }\n\n    .wrong-popup-panel {\n      position: relative;\n      z-index: 1;\n      min-width: 0;\n      min-height: 0;\n      display: grid;\n      border-radius: 8px;\n      overflow: hidden;\n      background: rgba(247, 243, 232, 0.08);\n    }\n\n    .wrong-carousel {\n      position: relative;\n      min-height: 0;\n      display: grid;\n      grid-template-rows: minmax(0, 1fr) auto;\n      gap: 12px;\n    }\n\n    .wrong-carousel-window {\n      min-height: 0;\n      overflow: hidden;\n      border: 0;\n      border-radius: 8px;\n      background: rgba(247, 243, 232, 0.08);\n    }\n\n    .wrong-carousel-track {\n      display: flex;\n      width: 200%;\n      height: 100%;\n      transition: transform 320ms ease;\n    }\n\n    .wrong-carousel-slide {\n      flex: 0 0 50%;\n      margin: 0;\n    }\n\n    .wrong-carousel-slide img {\n      display: block;\n      width: 100%;\n      height: 100%;\n      object-fit: contain;\n      padding: 0;\n    }\n\n    .wrong-slide-two-toggle:checked ~ .wrong-carousel-window .wrong-carousel-track {\n      transform: translateX(-50%);\n    }\n\n    .wrong-carousel-controls {\n      display: grid;\n      grid-template-columns: minmax(52px, 0.12fr) minmax(52px, 0.12fr) auto;\n      gap: 10px;\n      align-items: center;\n      justify-content: center;\n    }\n\n    .wrong-carousel-controls label {\n      min-width: 42px;\n      padding: 0 12px;\n      background: rgba(35, 70, 56, 0.82);\n      font-size: 0.92rem;\n    }\n\n    .wrong-slide-one-toggle:checked ~ .wrong-carousel-controls .wrong-dot-one,\n    .wrong-slide-two-toggle:checked ~ .wrong-carousel-controls .wrong-dot-two {\n      background: var(--gold);\n      color: var(--ink);\n    }\n\n    .wrong-popup-close {\n      padding: 0 14px;\n      background: rgba(91, 58, 36, 0.86);\n      color: var(--paper);\n    }\n\n    .market-image-story {\n      width: min(100%, 1180px);\n      margin-inline: auto;\n      border: 1px solid rgba(91, 58, 36, 0.18);\n      border-radius: 8px;\n      padding: clamp(18px, 3vw, 30px);\n      background:\n        linear-gradient(145deg, rgba(247, 243, 232, 0.96), rgba(232, 216, 184, 0.68)),\n        radial-gradient(circle at 10% 0%, rgba(185, 146, 69, 0.14), transparent 38%);\n      box-shadow: 0 20px 42px rgba(91, 58, 36, 0.14);\n    }\n\n    .market-image-story::after {\n      content: \"\";\n      display: block;\n      clear: both;\n    }\n\n    .market-theology-visual {\n      float: right;\n      width: min(46%, 520px);\n      margin: 0 0 clamp(16px, 2.4vw, 26px) clamp(20px, 3vw, 38px);\n      border: 1px solid rgba(91, 58, 36, 0.18);\n      border-radius: 8px;\n      overflow: hidden;\n      background: rgba(255, 255, 255, 0.62);\n      box-shadow: 0 18px 34px rgba(91, 58, 36, 0.16);\n    }\n\n    .market-theology-visual img {\n      display: block;\n      width: 100%;\n      height: auto;\n      object-fit: contain;\n    }\n\n    .market-image-story p {\n      margin: 0 0 clamp(12px, 1.8vw, 18px);\n      color: var(--muted);\n      font-size: clamp(1rem, 1.45vw, 1.16rem);\n      line-height: 1.66;\n    }\n\n    .market-image-story p:last-child {\n      margin-bottom: 0;\n    }\n\n    .market-image-story .closing-line {\n      color: var(--forest);\n      font-weight: 750;\n    }\n\n    .scripture-reflection {\n      width: min(100%, 1180px);\n      margin-inline: auto;\n    }\n\n    .value-bars {\n      display: grid;\n      gap: 12px;\n      margin: 18px 0;\n    }\n\n    .value-row {\n      display: grid;\n      grid-template-columns: minmax(98px, 0.32fr) minmax(0, 1fr);\n      gap: 12px;\n      align-items: center;\n      color: var(--deep-kraft);\n      font-size: 0.9rem;\n      font-weight: 750;\n    }\n\n    .value-track {\n      min-height: 22px;\n      overflow: hidden;\n      border: 1px solid rgba(91, 58, 36, 0.16);\n      border-radius: 999px;\n      background: rgba(255, 255, 255, 0.58);\n    }\n\n    .value-fill {\n      display: flex;\n      min-height: 22px;\n      align-items: center;\n      justify-content: flex-end;\n      padding-right: 10px;\n      border-radius: 999px;\n      background: linear-gradient(90deg, var(--leaf), var(--gold));\n      color: var(--paper);\n      font-size: 0.78rem;\n      font-weight: 800;\n    }\n\n    .choice-list {\n      display: grid;\n      gap: 12px;\n      margin-top: 14px;\n    }\n\n    .choice-list .card {\n      display: grid;\n      gap: 6px;\n      box-shadow: none;\n    }\n\n    .ordinary-art-page {\n      min-height: calc(100vh - 120px);\n      display: grid;\n      gap: clamp(24px, 4vw, 42px);\n      align-content: start;\n      border-radius: 8px;\n      background:\n        linear-gradient(180deg, rgba(247, 243, 232, 0.84), rgba(247, 243, 232, 0.94)),\n        radial-gradient(circle at 12% 0%, rgba(217, 154, 61, 0.12), transparent 34%);\n    }\n\n    .ordinary-story {\n      color: #76604f;\n    }\n\n    .ordinary-story::after {\n      content: \"\";\n      display: block;\n      clear: both;\n    }\n\n    .ordinary-hero {\n      float: left;\n      width: min(59%, 740px);\n      margin: 0 clamp(24px, 3vw, 42px) 18px 0;\n      border-radius: 8px;\n      object-fit: contain;\n      box-shadow: 0 18px 34px rgba(91, 58, 36, 0.16);\n    }\n\n    .ordinary-copy {\n      max-width: none;\n    }\n\n    .ordinary-copy p {\n      margin: 0 0 clamp(12px, 1.6vw, 18px);\n      color: #76604f;\n      font-size: clamp(1.08rem, 1.65vw, 1.38rem);\n      line-height: 1.62;\n    }\n\n    .ordinary-copy p:last-child {\n      margin-bottom: 0;\n    }\n\n    .ordinary-copy .ordinary-small {\n      max-width: 72ch;\n      margin-top: clamp(10px, 1.6vw, 18px);\n      padding-top: clamp(10px, 1.4vw, 16px);\n      border-top: 1px solid rgba(118, 96, 79, 0.18);\n      font-size: clamp(0.98rem, 1.35vw, 1.14rem);\n      line-height: 1.58;\n    }\n\n    .transparent-quote-row {\n      display: grid;\n      grid-template-columns: repeat(2, minmax(280px, 1fr));\n      gap: clamp(34px, 8vw, 110px);\n      align-items: end;\n      margin: 0;\n      padding: clamp(12px, 2.2vw, 20px) clamp(8px, 2vw, 18px);\n      border-radius: 8px;\n      background:\n        linear-gradient(90deg, rgba(247, 243, 232, 0.18), rgba(232, 216, 184, 0.32), rgba(247, 243, 232, 0.18));\n    }\n\n    .transparent-quote {\n      margin: 0;\n      border: 0;\n      background: transparent;\n      box-shadow: none;\n      display: grid;\n      place-items: end center;\n    }\n\n    .transparent-quote img {\n      display: block;\n      width: 100%;\n      max-width: 640px;\n      height: clamp(130px, 15vw, 178px);\n      object-fit: contain;\n      mix-blend-mode: multiply;\n      filter: drop-shadow(0 10px 12px rgba(91, 58, 36, 0.12));\n    }\n\n    .economics-step-page {\n      display: grid;\n      gap: clamp(18px, 3vw, 26px);\n      border: 1px solid rgba(91, 58, 36, 0.18);\n      border-radius: 8px;\n      padding: clamp(18px, 3vw, 28px);\n      background:\n        linear-gradient(145deg, rgba(247, 243, 232, 0.96), rgba(232, 216, 184, 0.72)),\n        radial-gradient(circle at 15% 0%, rgba(217, 154, 61, 0.14), transparent 36%);\n      box-shadow: 0 22px 48px rgba(91, 58, 36, 0.16);\n    }\n\n    .economics-step-header {\n      display: flex;\n      gap: 16px;\n      align-items: flex-start;\n      justify-content: space-between;\n    }\n\n    .economics-step-header h2,\n    .economics-step-header p {\n      margin: 0;\n    }\n\n    .economics-step-header h2 {\n      margin-top: 5px;\n      color: var(--forest);\n      font-size: clamp(1.65rem, 4vw, 2.55rem);\n      line-height: 1.08;\n    }\n\n    .completion-icon {\n      flex: 0 0 auto;\n      width: 36px;\n      height: 36px;\n      display: grid;\n      place-items: center;\n      border: 1px solid rgba(185, 146, 69, 0.44);\n      border-radius: 8px;\n      background: rgba(247, 243, 232, 0.72);\n      color: var(--forest);\n      font-weight: 850;\n      box-shadow: 0 10px 20px rgba(91, 58, 36, 0.1);\n    }\n\n    .economics-teaching-panel {\n      border: 1px solid rgba(91, 58, 36, 0.16);\n      border-radius: 8px;\n      padding: clamp(18px, 3vw, 28px);\n      background:\n        linear-gradient(180deg, rgba(247, 243, 232, 0.92), rgba(255, 255, 255, 0.55)),\n        radial-gradient(circle at 85% 8%, rgba(124, 143, 90, 0.1), transparent 34%);\n      box-shadow: 0 18px 38px rgba(91, 58, 36, 0.12);\n    }\n\n    .economics-hero-layout {\n      display: grid;\n      grid-template-columns: minmax(280px, 0.9fr) minmax(380px, 1.1fr);\n      gap: clamp(18px, 3vw, 28px);\n      align-items: stretch;\n      margin-top: clamp(14px, 2vw, 18px);\n    }\n\n    .economics-hero-copy {\n      display: grid;\n      grid-template-rows: minmax(0, 1fr) minmax(0, 1fr);\n      gap: clamp(16px, 2.4vw, 22px);\n      min-width: 0;\n    }\n\n    .economics-hero-copy .teaching-section {\n      display: grid;\n      align-content: center;\n      margin-top: 0;\n    }\n\n    .economics-square-image {\n      display: block;\n      width: 100%;\n      height: 100%;\n      min-height: clamp(520px, 58vw, 650px);\n      margin: 0;\n      border: 1px solid rgba(91, 58, 36, 0.18);\n      border-radius: 8px;\n      object-fit: cover;\n      object-position: center;\n      background: var(--cream);\n      box-shadow: 0 18px 34px rgba(91, 58, 36, 0.18);\n    }\n\n    .teaching-section {\n      margin-top: clamp(16px, 2.5vw, 22px);\n      overflow: hidden;\n      border: 1px solid rgba(91, 58, 36, 0.13);\n      border-left: 4px solid rgba(185, 146, 69, 0.72);\n      border-radius: 8px;\n      padding: clamp(12px, 1.8vw, 16px) clamp(14px, 2vw, 18px);\n      background:\n        linear-gradient(145deg, rgba(255, 255, 255, 0.46), rgba(247, 243, 232, 0.7)),\n        radial-gradient(circle at 100% 0%, rgba(185, 146, 69, 0.1), transparent 34%);\n      box-shadow: 0 12px 26px rgba(91, 58, 36, 0.08);\n    }\n\n    .teaching-section.everyday-life-section {\n      border-left-color: rgba(79, 107, 58, 0.86);\n      background:\n        linear-gradient(145deg, rgba(124, 143, 90, 0.14), rgba(247, 243, 232, 0.76)),\n        radial-gradient(circle at 100% 0%, rgba(79, 107, 58, 0.12), transparent 34%);\n    }\n\n    .teaching-section.misunderstanding-section {\n      border-color: rgba(217, 154, 61, 0.34);\n      border-left-color: var(--amber);\n      background:\n        linear-gradient(145deg, rgba(217, 154, 61, 0.2), rgba(247, 243, 232, 0.78)),\n        radial-gradient(circle at 100% 0%, rgba(154, 107, 63, 0.14), transparent 34%);\n    }\n\n    .teaching-section.misunderstanding-section h3 {\n      color: var(--deep-kraft);\n    }\n\n    .teaching-section.takeaway-section {\n      border-left-color: rgba(35, 70, 56, 0.84);\n      background:\n        linear-gradient(145deg, rgba(35, 70, 56, 0.1), rgba(247, 243, 232, 0.76)),\n        radial-gradient(circle at 100% 0%, rgba(185, 146, 69, 0.12), transparent 34%);\n    }\n\n    .teaching-section:first-of-type {\n      margin-top: 0;\n    }\n\n    .teaching-section h3,\n    .teaching-section p {\n      margin: 0;\n    }\n\n    .teaching-section h3 {\n      margin-bottom: 10px;\n      color: var(--forest);\n      font-size: clamp(1.05rem, 2vw, 1.22rem);\n      line-height: 1.2;\n    }\n\n    .teaching-section p + p {\n      margin-top: 22px;\n    }\n\n    .teaching-section p,\n    .economics-list li {\n      color: var(--deep-kraft);\n      font-size: clamp(0.96rem, 1.55vw, 1.08rem);\n      line-height: 1.72;\n    }\n\n    .economics-list {\n      grid-template-columns: repeat(auto-fit, minmax(210px, 1fr));\n      gap: 8px 18px;\n      margin: 9px 0 0;\n      padding-left: 18px;\n    }\n\n    .economics-visual-card {\n      clear: both;\n      margin: clamp(18px, 3vw, 26px) 0;\n      border: 1px solid rgba(91, 58, 36, 0.16);\n      border-radius: 8px;\n      padding: clamp(10px, 1.8vw, 14px);\n      background:\n        linear-gradient(145deg, rgba(247, 243, 232, 0.86), rgba(255, 255, 255, 0.58)),\n        radial-gradient(circle at 12% 0%, rgba(217, 154, 61, 0.12), transparent 32%);\n      box-shadow: 0 16px 34px rgba(91, 58, 36, 0.12);\n    }\n\n    .economics-visual-card img {\n      display: block;\n      width: 100%;\n      max-height: 520px;\n      object-fit: contain;\n      border-radius: 6px;\n    }\n\n    .quote-card-row,\n    .concept-card-row {\n      display: grid;\n      grid-template-columns: repeat(2, minmax(0, 1fr));\n      gap: clamp(14px, 2.5vw, 20px);\n    }\n\n    .quote-card-row {\n      align-items: stretch;\n    }\n\n    .quote-card {\n      display: grid;\n      place-items: center;\n      border: 1px solid rgba(185, 146, 69, 0.34);\n      border-left: 5px solid var(--gold);\n      border-radius: 8px;\n      padding: 12px;\n      background: rgba(247, 243, 232, 0.74);\n      box-shadow: 0 16px 34px rgba(91, 58, 36, 0.12);\n    }\n\n    .quote-card img {\n      width: 100%;\n      max-height: 210px;\n      object-fit: contain;\n      mix-blend-mode: multiply;\n      filter: drop-shadow(0 10px 12px rgba(91, 58, 36, 0.12));\n    }\n\n    .concept-card-row {\n      grid-template-columns: repeat(3, minmax(0, 1fr));\n    }\n\n    .concept-card {\n      border: 1px solid rgba(91, 58, 36, 0.15);\n      border-radius: 8px;\n      padding: 16px;\n      background: rgba(255, 255, 255, 0.5);\n      box-shadow: 0 14px 28px rgba(91, 58, 36, 0.1);\n    }\n\n    .concept-card strong {\n      display: block;\n      margin-bottom: 7px;\n      color: var(--gold);\n      font-size: 0.76rem;\n      text-transform: uppercase;\n    }\n\n    .concept-card h3,\n    .concept-card p {\n      margin: 0;\n    }\n\n    .concept-card h3 {\n      margin-bottom: 7px;\n      color: var(--forest);\n      font-size: 1.04rem;\n    }\n\n    .concept-card p {\n      color: var(--muted);\n      line-height: 1.5;\n    }\n\n    .economics-highlight {\n      border: 1px solid rgba(185, 146, 69, 0.36);\n      border-left: 5px solid var(--gold);\n      border-radius: 8px;\n      padding: 16px 18px;\n      background: rgba(217, 154, 61, 0.1);\n      box-shadow: 0 14px 28px rgba(91, 58, 36, 0.1);\n    }\n\n    .economics-highlight h3,\n    .economics-highlight p {\n      margin: 0;\n    }\n\n    .economics-highlight h3 {\n      margin-bottom: 7px;\n      color: var(--forest);\n    }\n\n    .economics-choice-chart {\n      display: grid;\n      gap: 12px;\n      border: 1px solid rgba(91, 58, 36, 0.15);\n      border-radius: 8px;\n      padding: 16px;\n      background: rgba(255, 255, 255, 0.48);\n      box-shadow: 0 14px 28px rgba(91, 58, 36, 0.1);\n    }\n\n    .economics-choice-chart h3 {\n      margin: 0;\n      color: var(--forest);\n    }\n\n    .choice-chart-row {\n      display: grid;\n      grid-template-columns: minmax(90px, 0.18fr) minmax(0, 1fr);\n      gap: 12px;\n      align-items: center;\n    }\n\n    .choice-chart-row strong {\n      color: var(--deep-kraft);\n    }\n\n    .choice-chart-tags {\n      display: flex;\n      gap: 8px;\n      flex-wrap: wrap;\n    }\n\n    .choice-chart-tags span {\n      border: 1px solid rgba(79, 107, 58, 0.2);\n      border-radius: 999px;\n      padding: 6px 10px;\n      background: rgba(124, 143, 90, 0.17);\n      color: var(--forest);\n      font-size: 0.86rem;\n      font-weight: 750;\n    }\n\n    .faith-reflection {\n      border-color: rgba(217, 154, 61, 0.44);\n      border-left-color: var(--amber);\n      background:\n        linear-gradient(145deg, rgba(217, 154, 61, 0.13), rgba(247, 243, 232, 0.74));\n    }\n\n    .pillars-page {\n      display: grid;\n      gap: clamp(18px, 3vw, 28px);\n    }\n\n    .pillars-hero {\n      display: grid;\n      gap: 10px;\n      justify-items: center;\n      text-align: center;\n      padding: clamp(18px, 3vw, 28px);\n      border: 1px solid rgba(91, 58, 36, 0.18);\n      border-radius: 8px;\n      background:\n        linear-gradient(145deg, rgba(247, 243, 232, 0.94), rgba(232, 216, 184, 0.7)),\n        radial-gradient(circle at 50% 0%, rgba(217, 154, 61, 0.16), transparent 36%);\n      box-shadow: 0 18px 42px rgba(91, 58, 36, 0.14);\n    }\n\n    .pillars-hero h2 {\n      max-width: 980px;\n      margin: 0;\n      font-family: Georgia, \"Times New Roman\", serif;\n      color: var(--forest);\n      font-size: clamp(2rem, 6vw, 4.4rem);\n      line-height: 1;\n    }\n\n    .pillars-hero p {\n      max-width: 760px;\n      margin: 0;\n      color: var(--deep-kraft);\n      font-size: clamp(0.98rem, 1.5vw, 1.12rem);\n    }\n\n    .pillars-grid {\n      position: relative;\n      display: grid;\n      grid-template-columns: repeat(2, minmax(260px, 1fr));\n      gap: clamp(16px, 2.5vw, 26px);\n      padding: clamp(12px, 2vw, 18px);\n      border-radius: 8px;\n      overflow: visible;\n      background:\n        linear-gradient(180deg, rgba(247, 243, 232, 0.42), rgba(232, 216, 184, 0.36)),\n        radial-gradient(circle at 0% 100%, rgba(185, 146, 69, 0.12), transparent 30%);\n    }\n\n    .pillar-card-shell {\n      position: relative;\n      min-height: clamp(210px, 22vw, 280px);\n      z-index: 0;\n    }\n\n    .pillar-card-shell:has(.pillar-toggle:checked) {\n      z-index: 1000;\n    }\n\n    .pillar-toggle {\n      position: absolute;\n      width: 1px;\n      height: 1px;\n      opacity: 0;\n      pointer-events: none;\n    }\n\n    .pillar-flip-card {\n      position: relative;\n      display: block;\n      width: 100%;\n      height: 100%;\n      min-height: inherit;\n      cursor: pointer;\n      transform-style: preserve-3d;\n      transition:\n        transform 420ms ease,\n        filter 180ms ease;\n    }\n\n    .pillar-toggle:checked + .pillar-flip-card {\n      z-index: 4;\n      transform: translateY(-2px) scale(1.01);\n      filter: drop-shadow(0 24px 30px rgba(91, 58, 36, 0.18));\n    }\n\n    .pillar-toggle:focus-visible + .pillar-flip-card .pillar-face {\n      outline: 3px solid rgba(185, 146, 69, 0.45);\n      outline-offset: 3px;\n    }\n\n    .pillar-face {\n      position: absolute;\n      inset: 0;\n      overflow: hidden;\n      border: 2px solid rgba(185, 146, 69, 0.58);\n      border-radius: 8px;\n      backface-visibility: hidden;\n      box-shadow:\n        0 18px 34px rgba(91, 58, 36, 0.13),\n        inset 0 1px 0 rgba(255, 255, 255, 0.7);\n    }\n\n    .pillar-front {\n      display: grid;\n      grid-template-columns: minmax(112px, 0.42fr) minmax(0, 1fr);\n      gap: clamp(14px, 2vw, 22px);\n      align-items: center;\n      padding: clamp(22px, 3vw, 32px);\n      background:\n        linear-gradient(145deg, rgba(247, 243, 232, 0.96), rgba(232, 216, 184, 0.56)),\n        radial-gradient(circle at 0% 100%, rgba(185, 146, 69, 0.18), transparent 34%);\n    }\n\n    .pillar-icon {\n      display: grid;\n      place-items: center;\n      min-height: 128px;\n      color: var(--gold);\n    }\n\n    .pillar-icon img {\n      display: block;\n      width: min(150px, 100%);\n      height: auto;\n      max-height: 150px;\n      object-fit: contain;\n      filter: drop-shadow(0 10px 10px rgba(91, 58, 36, 0.16));\n    }\n\n    .pillar-front h3,\n    .pillar-front p,\n    .pillar-popup-card h3,\n    .pillar-popup-card p {\n      margin: 0;\n    }\n\n    .pillar-front h3 {\n      color: var(--forest);\n      font-family: Georgia, \"Times New Roman\", serif;\n      font-size: clamp(1.75rem, 3.5vw, 3.15rem);\n      line-height: 1;\n    }\n\n    .pillar-front p {\n      max-width: 30rem;\n      margin-top: 10px;\n      color: var(--deep-kraft);\n      font-size: clamp(0.95rem, 1.35vw, 1.08rem);\n      line-height: 1.35;\n    }\n\n    .pillar-front span {\n      display: inline-flex;\n      width: fit-content;\n      margin-top: 14px;\n      border-radius: 999px;\n      padding: 6px 10px;\n      background: rgba(185, 146, 69, 0.16);\n      color: var(--deep-kraft);\n      font-size: 0.78rem;\n      font-weight: 800;\n      text-transform: uppercase;\n    }\n\n    .pillar-popup {\n      position: fixed;\n      inset: 0;\n      z-index: 9999;\n      isolation: isolate;\n      display: grid;\n      place-items: center;\n      padding: clamp(16px, 4vw, 38px);\n      background: rgba(23, 19, 15, 0.68);\n      backdrop-filter: blur(5px);\n      opacity: 0;\n      pointer-events: none;\n      visibility: hidden;\n      transition:\n        opacity 180ms ease,\n        visibility 180ms ease;\n    }\n\n    .pillar-toggle:checked ~ .pillar-popup {\n      opacity: 1;\n      pointer-events: auto;\n      visibility: visible;\n    }\n\n    .pillar-popup-backdrop {\n      position: absolute;\n      inset: 0;\n      cursor: pointer;\n    }\n\n    .pillar-popup-card {\n      position: relative;\n      z-index: 1;\n      width: min(760px, calc(100vw - 28px));\n      max-height: min(84vh, 680px);\n      display: grid;\n      gap: clamp(14px, 2vw, 18px);\n      overflow: auto;\n      border: 2px solid rgba(185, 146, 69, 0.58);\n      border-radius: 8px;\n      padding: clamp(20px, 3vw, 32px);\n      background:\n        linear-gradient(145deg, #f7f3e8, #f0e5cf),\n        radial-gradient(circle at 100% 0%, rgba(79, 107, 58, 0.12), transparent 36%);\n      box-shadow: 0 34px 90px rgba(23, 19, 15, 0.52);\n      transform: translateY(18px) rotateX(4deg) scale(0.97);\n      transform-origin: center;\n      transition: transform 220ms ease;\n    }\n\n    .pillar-toggle:checked ~ .pillar-popup .pillar-popup-card {\n      transform: translateY(0) rotateX(0) scale(1);\n    }\n\n    .pillar-popup-close {\n      position: sticky;\n      top: 0;\n      justify-self: end;\n      border: 1px solid rgba(91, 58, 36, 0.2);\n      border-radius: 999px;\n      padding: 7px 12px;\n      background: #f7f3e8;\n      color: var(--deep-kraft);\n      cursor: pointer;\n      font-size: 0.78rem;\n      font-weight: 850;\n      text-transform: uppercase;\n      box-shadow: 0 8px 16px rgba(91, 58, 36, 0.12);\n    }\n\n    .pillar-popup-card strong {\n      color: var(--gold);\n      font-size: 0.76rem;\n      text-transform: uppercase;\n    }\n\n    .pillar-popup-card h3 {\n      color: var(--forest);\n      max-width: 100%;\n      font-size: clamp(1.55rem, 3vw, 2.25rem);\n      line-height: 1.16;\n      text-wrap: balance;\n    }\n\n    .pillar-popup-card p {\n      color: var(--muted);\n      max-width: 68ch;\n      font-size: clamp(1.04rem, 1.55vw, 1.18rem);\n      line-height: 1.65;\n    }\n\n    .complete-button {\n      display: inline-flex;\n      min-height: 42px;\n      align-items: center;\n      justify-content: center;\n      margin-top: 22px;\n      padding: 0 16px;\n      border: 1px solid var(--forest);\n      border-radius: 8px;\n      background: linear-gradient(145deg, var(--forest), var(--ubuntu));\n      color: var(--paper);\n      font: inherit;\n      font-weight: 750;\n      cursor: pointer;\n      box-shadow: 0 12px 24px rgba(35, 70, 56, 0.22);\n      transition:\n        background 160ms ease,\n        transform 160ms ease,\n        box-shadow 160ms ease;\n    }\n\n    .complete-button:hover {\n      background: linear-gradient(145deg, #1d3a2f, var(--forest));\n      box-shadow: 0 14px 28px rgba(35, 70, 56, 0.26);\n      transform: translateY(-1px);\n    }\n\n    @media (max-width: 640px) {\n      .comparison {\n        grid-template-columns: 1fr;\n      }\n\n      .comparison div:first-child {\n        border-right: 0;\n        border-bottom: 1px solid rgba(91, 58, 36, 0.18);\n      }\n\n      .value-row {\n        grid-template-columns: 1fr;\n        gap: 6px;\n      }\n\n      .ordinary-hero {\n        float: none;\n        width: 100%;\n        margin: 0 0 18px;\n      }\n\n      .ordinary-copy p {\n        font-size: 1rem;\n        line-height: 1.56;\n      }\n\n      .market-theology-visual {\n        float: none;\n        width: 100%;\n        margin: 0 0 18px;\n      }\n\n      .audio-discussion-button {\n        width: min(100%, 360px);\n      }\n\n      .audio-popup-panel {\n        min-height: min(72vh, 560px);\n        padding: 18px;\n      }\n\n      .soundwave {\n        min-height: 130px;\n      }\n\n      .wrong-thinking-images,\n      .wrong-card-grid {\n        grid-template-columns: 1fr;\n      }\n\n      .wrong-thinking-image img {\n        min-height: 0;\n      }\n\n      .wrong-flip-card {\n        min-height: 0;\n      }\n\n      .market-image-story p {\n        font-size: 1rem;\n        line-height: 1.58;\n      }\n\n      .transparent-quote-row {\n        grid-template-columns: 1fr;\n      }\n\n      .economics-step-header {\n        align-items: flex-start;\n      }\n\n      .economics-hero-layout {\n        grid-template-columns: 1fr;\n      }\n\n      .economics-square-image {\n        height: auto;\n        min-height: 0;\n        object-fit: contain;\n      }\n\n      .quote-card-row,\n      .concept-card-row {\n        grid-template-columns: 1fr;\n      }\n\n      .pillars-grid {\n        grid-template-columns: 1fr;\n      }\n\n      .pillar-card-shell {\n        min-height: 250px;\n      }\n\n      .pillar-front {\n        grid-template-columns: 1fr;\n        justify-items: center;\n        text-align: center;\n      }\n\n      .choice-chart-row {\n        grid-template-columns: 1fr;\n        gap: 7px;\n      }\n    }\n  </style>\n  <main class=\"rich-step\" data-rich-lesson-step>\n    \n      <section class=\"pillars-page\">\n        <section class=\"pillars-hero\">\n          <p class=\"eyebrow\">Practical life</p>\n          <h2>The Four Pillars of Economic Activity</h2>\n          <p>\n            Tap a pillar to open a detail popup and see how property, relationships, work, and consumption shape daily\n            choices for individuals, businesses, and governments.\n          </p>\n        </section>\n\n        <div class=\"pillars-grid\" aria-label=\"Four pillars of economic activity\">\n          <input class=\"pillar-toggle pillar-reset\" type=\"radio\" name=\"level-1-session-1-the-daily-grind-pillar-detail\" id=\"level-1-session-1-the-daily-grind-pillar-none\" checked />\n\n          <div class=\"pillar-card-shell\">\n            <input class=\"pillar-toggle\" type=\"radio\" name=\"level-1-session-1-the-daily-grind-pillar-detail\" id=\"level-1-session-1-the-daily-grind-pillar-property\" />\n            <label class=\"pillar-flip-card\" for=\"level-1-session-1-the-daily-grind-pillar-property\">\n              <div class=\"pillar-face pillar-front\">\n                <div class=\"pillar-icon\" aria-hidden=\"true\">\n                  <img src=\"/Faithonomics/assets/pillar-property-clean.png\" alt=\"\" />\n                </div>\n                <div>\n                  <h3>Property</h3>\n                  <p>What we own, manage, and protect.</p>\n                  <span>Click to find out more</span>\n                </div>\n              </div>\n            </label>\n            <div class=\"pillar-popup\" role=\"dialog\" aria-label=\"Property detail\">\n              <label class=\"pillar-popup-backdrop\" for=\"level-1-session-1-the-daily-grind-pillar-none\" aria-label=\"Close property detail\"></label>\n              <div class=\"pillar-popup-card\">\n                <label class=\"pillar-popup-close\" for=\"level-1-session-1-the-daily-grind-pillar-none\">Close</label>\n                <strong>Property</strong>\n                <h3>What we own, manage, and protect</h3>\n                <p>For individuals, property includes money, a home, tools, time, and personal belongings. We choose whether to use these gifts for fear, pride, comfort, service, or stewardship.</p>\n                <p>For businesses, property includes stock, equipment, buildings, ideas, and capital. These assets should create value without exploiting people.</p>\n                <p>For governments, property includes laws, rights, land use, and public resources. Good policy protects ownership while also caring for public welfare.</p>\n              </div>\n            </div>\n          </div>\n\n          <div class=\"pillar-card-shell\">\n            <input class=\"pillar-toggle\" type=\"radio\" name=\"level-1-session-1-the-daily-grind-pillar-detail\" id=\"level-1-session-1-the-daily-grind-pillar-relationships\" />\n            <label class=\"pillar-flip-card\" for=\"level-1-session-1-the-daily-grind-pillar-relationships\">\n              <div class=\"pillar-face pillar-front\">\n                <div class=\"pillar-icon\" aria-hidden=\"true\">\n                  <img src=\"/Faithonomics/assets/pillar-relationships-clean.png\" alt=\"\" />\n                </div>\n                <div>\n                  <h3>Relationships</h3>\n                  <p>Who we trust, trade with, and serve.</p>\n                  <span>Click to find out more</span>\n                </div>\n              </div>\n            </label>\n            <div class=\"pillar-popup\" role=\"dialog\" aria-label=\"Relationships detail\">\n              <label class=\"pillar-popup-backdrop\" for=\"level-1-session-1-the-daily-grind-pillar-none\" aria-label=\"Close relationships detail\"></label>\n              <div class=\"pillar-popup-card\">\n                <label class=\"pillar-popup-close\" for=\"level-1-session-1-the-daily-grind-pillar-none\">Close</label>\n                <strong>Relationships</strong>\n                <h3>Who we trust, trade with, and serve</h3>\n                <p>For individuals, relationships affect family budgets, friendships, borrowing, lending, and daily support. Our economic choices can build trust or damage it.</p>\n                <p>For businesses, relationships include customers, workers, suppliers, competitors, and the community. Fair dealing creates long-term strength.</p>\n                <p>For governments, relationships include trade, diplomacy, social support, and peace. Public decisions can strengthen or weaken the bonds of society.</p>\n              </div>\n            </div>\n          </div>\n\n          <div class=\"pillar-card-shell\">\n            <input class=\"pillar-toggle\" type=\"radio\" name=\"level-1-session-1-the-daily-grind-pillar-detail\" id=\"level-1-session-1-the-daily-grind-pillar-work\" />\n            <label class=\"pillar-flip-card\" for=\"level-1-session-1-the-daily-grind-pillar-work\">\n              <div class=\"pillar-face pillar-front\">\n                <div class=\"pillar-icon\" aria-hidden=\"true\">\n                  <img src=\"/Faithonomics/assets/pillar-work-clean.png\" alt=\"\" />\n                </div>\n                <div>\n                  <h3>Work</h3>\n                  <p>How effort becomes service.</p>\n                  <span>Click to find out more</span>\n                </div>\n              </div>\n            </label>\n            <div class=\"pillar-popup\" role=\"dialog\" aria-label=\"Work detail\">\n              <label class=\"pillar-popup-backdrop\" for=\"level-1-session-1-the-daily-grind-pillar-none\" aria-label=\"Close work detail\"></label>\n              <div class=\"pillar-popup-card\">\n                <label class=\"pillar-popup-close\" for=\"level-1-session-1-the-daily-grind-pillar-none\">Close</label>\n                <strong>Work</strong>\n                <h3>How effort becomes service</h3>\n                <p>For individuals, work is a source of income, skill, dignity, and purpose. The question is not only, \"How much do I earn?\" but also, \"What kind of person am I becoming through my work?\"</p>\n                <p>For businesses, work creates jobs, products, services, and training. Good businesses organise labour in ways that respect people.</p>\n                <p>For governments, work connects to labour law, education, safety, fair wages, and economic growth. Wise policy helps people work with dignity.</p>\n              </div>\n            </div>\n          </div>\n\n          <div class=\"pillar-card-shell\">\n            <input class=\"pillar-toggle\" type=\"radio\" name=\"level-1-session-1-the-daily-grind-pillar-detail\" id=\"level-1-session-1-the-daily-grind-pillar-consumption\" />\n            <label class=\"pillar-flip-card\" for=\"level-1-session-1-the-daily-grind-pillar-consumption\">\n              <div class=\"pillar-face pillar-front\">\n                <div class=\"pillar-icon\" aria-hidden=\"true\">\n                  <img src=\"/Faithonomics/assets/pillar-consumption-clean.png\" alt=\"\" />\n                </div>\n                <div>\n                  <h3>Consumption</h3>\n                  <p>How we use resources to meet needs.</p>\n                  <span>Click to find out more</span>\n                </div>\n              </div>\n            </label>\n            <div class=\"pillar-popup\" role=\"dialog\" aria-label=\"Consumption detail\">\n              <label class=\"pillar-popup-backdrop\" for=\"level-1-session-1-the-daily-grind-pillar-none\" aria-label=\"Close consumption detail\"></label>\n              <div class=\"pillar-popup-card\">\n                <label class=\"pillar-popup-close\" for=\"level-1-session-1-the-daily-grind-pillar-none\">Close</label>\n                <strong>Consumption</strong>\n                <h3>How we use resources to meet needs</h3>\n                <p>For individuals, consumption includes food, clothing, transport, entertainment, and technology. Every purchase asks whether we are meeting a need, feeding greed, or serving a good purpose.</p>\n                <p>For businesses, consumption patterns shape production, pricing, advertising, and distribution. Companies must decide whether to serve real needs or only create more desire.</p>\n                <p>For governments, consumption affects access to goods, public services, taxation, and fairness. Good systems help people meet needs without wasting resources.</p>\n              </div>\n            </div>\n          </div>\n        </div>\n      </section>\n    \n    \n  </main>\n"},{"id":"level-1-session-1-the-daily-grind-art-of-living-well","kind":"customHtml","title":"Step 5: The Architecture of Choice","body":"\n  <style>\n    :root {\n      color-scheme: light;\n      --paper: #f7f3e8;\n      --cream: #e8d8b8;\n      --forest: #234638;\n      --ubuntu: #4f6b3a;\n      --leaf: #7c8f5a;\n      --gold: #b99245;\n      --amber: #d99a3d;\n      --kraft: #9a6b3f;\n      --deep-kraft: #5b3a24;\n      --ink: #17130f;\n      --muted: #5d6659;\n    }\n\n    * {\n      box-sizing: border-box;\n    }\n\n    body {\n      margin: 0;\n      font-family: \"Segoe UI\", system-ui, sans-serif;\n      background:\n        linear-gradient(180deg, rgba(247, 243, 232, 0.98), rgba(232, 216, 184, 0.74)),\n        radial-gradient(circle at 16% 10%, rgba(217, 154, 61, 0.16), transparent 32%);\n      color: var(--ink);\n    }\n\n    .rich-step {\n      min-height: 100vh;\n      padding: clamp(18px, 4vw, 34px);\n    }\n\n    h2,\n    h3,\n    p {\n      margin-top: 0;\n    }\n\n    h2 {\n      margin-bottom: 10px;\n      color: var(--forest);\n      font-size: clamp(1.65rem, 4vw, 2.6rem);\n      line-height: 1.08;\n    }\n\n    h3 {\n      margin-bottom: 8px;\n      color: var(--forest);\n      font-size: 1.08rem;\n    }\n\n    p {\n      color: var(--muted);\n      line-height: 1.62;\n    }\n\n    .intro {\n      width: 100%;\n      max-width: none;\n      margin-bottom: 22px;\n      font-size: 1rem;\n    }\n\n    .eyebrow {\n      margin-bottom: 8px;\n      color: var(--gold);\n      font-size: 0.78rem;\n      font-weight: 800;\n      letter-spacing: 0;\n      text-transform: uppercase;\n    }\n\n    .grid {\n      display: grid;\n      grid-template-columns: repeat(auto-fit, minmax(220px, 1fr));\n      gap: 14px;\n      margin: 18px 0;\n    }\n\n    .card,\n    .callout,\n    .comparison {\n      border: 1px solid rgba(91, 58, 36, 0.18);\n      border-radius: 8px;\n      background: rgba(255, 255, 255, 0.56);\n      box-shadow: 0 16px 34px rgba(91, 58, 36, 0.12);\n    }\n\n    .card {\n      padding: 16px;\n    }\n\n    .card strong {\n      display: block;\n      margin-bottom: 6px;\n      color: var(--deep-kraft);\n      font-size: 0.86rem;\n      text-transform: uppercase;\n    }\n\n    .pill {\n      display: inline-flex;\n      min-height: 28px;\n      align-items: center;\n      margin: 8px 6px 0 0;\n      padding: 0 10px;\n      border-radius: 999px;\n      background: rgba(124, 143, 90, 0.22);\n      color: var(--forest);\n      font-size: 0.82rem;\n      font-weight: 750;\n    }\n\n    .callout {\n      margin-top: 18px;\n      padding: 16px;\n      border-left: 5px solid var(--gold);\n      background: rgba(217, 154, 61, 0.1);\n    }\n\n    .comparison {\n      display: grid;\n      grid-template-columns: minmax(0, 1fr) minmax(0, 1fr);\n      overflow: hidden;\n    }\n\n    .comparison div {\n      padding: 14px;\n    }\n\n    .comparison div:first-child {\n      border-right: 1px solid rgba(91, 58, 36, 0.18);\n      background: rgba(35, 70, 56, 0.08);\n    }\n\n    ul {\n      display: grid;\n      gap: 9px;\n      margin: 10px 0 0;\n      padding-left: 18px;\n      color: var(--muted);\n      line-height: 1.5;\n    }\n\n    textarea {\n      width: 100%;\n      min-height: 150px;\n      margin-top: 12px;\n      border: 1px solid rgba(91, 58, 36, 0.22);\n      border-radius: 8px;\n      padding: 12px 14px;\n      background: rgba(255, 255, 255, 0.72);\n      color: var(--ink);\n      font: inherit;\n      line-height: 1.55;\n      resize: vertical;\n      box-shadow: inset 0 1px 0 rgba(255, 255, 255, 0.72);\n    }\n\n    textarea:focus {\n      outline: 3px solid rgba(185, 146, 69, 0.28);\n      outline-offset: 2px;\n    }\n\n    .market-theology-page {\n      display: grid;\n      gap: clamp(18px, 3vw, 26px);\n      align-items: stretch;\n      justify-items: center;\n    }\n\n    .audio-discussion {\n      width: min(100%, 1180px);\n      display: grid;\n      gap: 10px;\n      justify-items: center;\n      margin-inline: auto;\n    }\n\n    .audio-discussion-copy {\n      margin: 0;\n      color: var(--forest);\n      font-size: clamp(1rem, 1.6vw, 1.18rem);\n      font-weight: 800;\n      text-align: center;\n    }\n\n    .audio-discussion-toggle {\n      position: absolute;\n      width: 1px;\n      height: 1px;\n      opacity: 0;\n      pointer-events: none;\n    }\n\n    .audio-discussion-button {\n      width: min(100%, 480px);\n      display: block;\n      padding: 0;\n      border: 0;\n      border-radius: 0;\n      background: transparent;\n      box-shadow: none;\n      cursor: pointer;\n    }\n\n    .audio-discussion-button img {\n      display: block;\n      width: 100%;\n      height: auto;\n      object-fit: contain;\n      filter: drop-shadow(0 16px 22px rgba(91, 58, 36, 0.16));\n      transition: transform 180ms ease;\n    }\n\n    .audio-discussion-button:hover img {\n      transform: translateY(-2px);\n    }\n\n    .audio-popup {\n      position: fixed;\n      inset: 0;\n      z-index: 140;\n      display: none;\n      padding: clamp(18px, 3vw, 32px);\n      background: rgba(23, 19, 15, 0.94);\n    }\n\n    .audio-discussion-toggle:checked ~ .audio-popup {\n      display: grid;\n    }\n\n    .audio-popup-scrim {\n      position: absolute;\n      inset: 0;\n      cursor: pointer;\n    }\n\n    .audio-popup-panel {\n      position: relative;\n      z-index: 1;\n      width: min(100%, 980px);\n      min-height: min(72vh, 680px);\n      display: grid;\n      gap: clamp(20px, 4vw, 34px);\n      align-content: center;\n      justify-self: center;\n      align-self: center;\n      border: 1px solid rgba(232, 216, 184, 0.22);\n      border-radius: 8px;\n      padding: clamp(22px, 4vw, 48px);\n      background:\n        linear-gradient(145deg, rgba(247, 243, 232, 0.96), rgba(232, 216, 184, 0.84)),\n        radial-gradient(circle at 50% 0%, rgba(185, 146, 69, 0.18), transparent 42%);\n      box-shadow: 0 28px 70px rgba(0, 0, 0, 0.42);\n    }\n\n    .soundwave {\n      min-height: clamp(150px, 24vw, 240px);\n      display: flex;\n      gap: clamp(7px, 1.3vw, 14px);\n      align-items: center;\n      justify-content: center;\n      padding: clamp(16px, 3vw, 30px);\n    }\n\n    .soundwave span {\n      width: clamp(7px, 1.2vw, 13px);\n      height: 42%;\n      border-radius: 999px;\n      background: linear-gradient(180deg, var(--gold), var(--forest));\n      animation: soundwave-rise 1.05s ease-in-out infinite;\n      box-shadow: 0 10px 20px rgba(91, 58, 36, 0.16);\n    }\n\n    .soundwave span:nth-child(2) {\n      animation-delay: -0.86s;\n    }\n\n    .soundwave span:nth-child(3) {\n      animation-delay: -0.68s;\n    }\n\n    .soundwave span:nth-child(4) {\n      animation-delay: -0.5s;\n    }\n\n    .soundwave span:nth-child(5) {\n      animation-delay: -0.32s;\n    }\n\n    .soundwave span:nth-child(6) {\n      animation-delay: -0.14s;\n    }\n\n    .soundwave span:nth-child(7) {\n      animation-delay: -0.76s;\n    }\n\n    .soundwave span:nth-child(8) {\n      animation-delay: -0.58s;\n    }\n\n    .soundwave span:nth-child(9) {\n      animation-delay: -0.4s;\n    }\n\n    .soundwave span:nth-child(10) {\n      animation-delay: -0.22s;\n    }\n\n    @keyframes soundwave-rise {\n      0%,\n      100% {\n        transform: scaleY(0.34);\n      }\n\n      50% {\n        transform: scaleY(1);\n      }\n    }\n\n    .audio-popup audio {\n      width: min(100%, 760px);\n      justify-self: center;\n      accent-color: var(--forest);\n    }\n\n    .audio-popup-close {\n      min-height: 42px;\n      width: fit-content;\n      display: inline-flex;\n      align-items: center;\n      justify-content: center;\n      justify-self: center;\n      border: 1px solid rgba(35, 70, 56, 0.18);\n      border-radius: 8px;\n      padding: 0 16px;\n      background: var(--forest);\n      color: var(--paper);\n      font-weight: 800;\n      cursor: pointer;\n      transition:\n        background 160ms ease,\n        transform 160ms ease;\n    }\n\n    .audio-popup-close:hover {\n      background: #1d3a2f;\n      transform: translateY(-1px);\n    }\n\n    .wrong-thinking-section {\n      width: min(100%, 1180px);\n      display: grid;\n      gap: clamp(16px, 2.6vw, 24px);\n      margin-inline: auto;\n    }\n\n    .wrong-thinking-section h2 {\n      margin: 0;\n      color: var(--forest);\n      font-size: clamp(1.75rem, 4vw, 2.7rem);\n      line-height: 1.08;\n    }\n\n    .scholars-heading {\n      margin: clamp(6px, 1.4vw, 12px) 0 0;\n      color: var(--deep-kraft);\n      font-size: clamp(1.2rem, 2.4vw, 1.7rem);\n      font-weight: 850;\n      text-align: center;\n    }\n\n    .wrong-thinking-images,\n    .wrong-card-grid {\n      display: grid;\n      grid-template-columns: repeat(2, minmax(0, 1fr));\n      gap: clamp(14px, 2.4vw, 22px);\n      width: 100%;\n    }\n\n    .wrong-thinking-image {\n      border: 1px solid rgba(91, 58, 36, 0.18);\n      border-radius: 8px;\n      padding: clamp(10px, 1.8vw, 18px);\n      background: rgba(255, 255, 255, 0.58);\n      box-shadow: 0 18px 36px rgba(91, 58, 36, 0.14);\n    }\n\n    .wrong-thinking-image:nth-child(1) {\n      background:\n        linear-gradient(145deg, rgba(210, 225, 194, 0.96), rgba(124, 143, 90, 0.34)),\n        radial-gradient(circle at 12% 0%, rgba(35, 70, 56, 0.16), transparent 42%);\n    }\n\n    .wrong-thinking-image:nth-child(2) {\n      background:\n        linear-gradient(145deg, rgba(236, 214, 151, 0.96), rgba(217, 154, 61, 0.28)),\n        radial-gradient(circle at 92% 0%, rgba(91, 58, 36, 0.14), transparent 42%);\n    }\n\n    .wrong-thinking-image {\n      margin: 0;\n      overflow: hidden;\n    }\n\n    .wrong-thinking-image img {\n      display: block;\n      width: 100%;\n      height: 100%;\n      min-height: clamp(280px, 34vw, 430px);\n      object-fit: contain;\n      border-radius: 6px;\n      background: rgba(247, 243, 232, 0.28);\n    }\n\n    .wrong-flip-card {\n      position: relative;\n      aspect-ratio: 4 / 3;\n      min-height: 0;\n    }\n\n    .wrong-flip-toggle,\n    .wrong-slide-toggle {\n      position: absolute;\n      width: 1px;\n      height: 1px;\n      opacity: 0;\n      pointer-events: none;\n    }\n\n    .wrong-flip-cover {\n      position: absolute;\n      inset: 0;\n      overflow: hidden;\n      border-radius: 0;\n      background: transparent;\n      box-shadow: none;\n      cursor: pointer;\n    }\n\n    .wrong-flip-cover img {\n      display: block;\n      width: 100%;\n      height: 100%;\n      object-fit: contain;\n      object-position: center;\n      transition: transform 220ms ease;\n    }\n\n    .wrong-flip-cover:hover img {\n      transform: none;\n    }\n\n    .wrong-flip-cta,\n    .wrong-popup-close,\n    .wrong-carousel-controls label {\n      min-height: 42px;\n      display: inline-flex;\n      align-items: center;\n      justify-content: center;\n      border: 1px solid rgba(35, 70, 56, 0.18);\n      border-radius: 8px;\n      background: var(--forest);\n      color: var(--paper);\n      font-weight: 800;\n      cursor: pointer;\n      transition:\n        background 160ms ease,\n        transform 160ms ease;\n    }\n\n    .wrong-flip-cta {\n      position: absolute;\n      right: clamp(14px, 2vw, 20px);\n      bottom: clamp(14px, 2vw, 20px);\n      padding: 0 18px;\n      background: rgba(35, 70, 56, 0.92);\n      box-shadow: 0 12px 26px rgba(23, 19, 15, 0.2);\n    }\n\n    .wrong-flip-cta:hover,\n    .wrong-popup-close:hover,\n    .wrong-carousel-controls label:hover {\n      background: #1d3a2f;\n      transform: translateY(-1px);\n    }\n\n    .wrong-carousel-popup {\n      position: fixed;\n      inset: 0;\n      z-index: 120;\n      display: none;\n      padding: clamp(12px, 2vw, 24px);\n      background: rgba(23, 19, 15, 0.94);\n    }\n\n    .wrong-flip-toggle:checked ~ .wrong-carousel-popup {\n      display: grid;\n    }\n\n    .wrong-popup-scrim {\n      position: absolute;\n      inset: 0;\n      cursor: pointer;\n    }\n\n    .wrong-popup-panel {\n      position: relative;\n      z-index: 1;\n      min-width: 0;\n      min-height: 0;\n      display: grid;\n      border-radius: 8px;\n      overflow: hidden;\n      background: rgba(247, 243, 232, 0.08);\n    }\n\n    .wrong-carousel {\n      position: relative;\n      min-height: 0;\n      display: grid;\n      grid-template-rows: minmax(0, 1fr) auto;\n      gap: 12px;\n    }\n\n    .wrong-carousel-window {\n      min-height: 0;\n      overflow: hidden;\n      border: 0;\n      border-radius: 8px;\n      background: rgba(247, 243, 232, 0.08);\n    }\n\n    .wrong-carousel-track {\n      display: flex;\n      width: 200%;\n      height: 100%;\n      transition: transform 320ms ease;\n    }\n\n    .wrong-carousel-slide {\n      flex: 0 0 50%;\n      margin: 0;\n    }\n\n    .wrong-carousel-slide img {\n      display: block;\n      width: 100%;\n      height: 100%;\n      object-fit: contain;\n      padding: 0;\n    }\n\n    .wrong-slide-two-toggle:checked ~ .wrong-carousel-window .wrong-carousel-track {\n      transform: translateX(-50%);\n    }\n\n    .wrong-carousel-controls {\n      display: grid;\n      grid-template-columns: minmax(52px, 0.12fr) minmax(52px, 0.12fr) auto;\n      gap: 10px;\n      align-items: center;\n      justify-content: center;\n    }\n\n    .wrong-carousel-controls label {\n      min-width: 42px;\n      padding: 0 12px;\n      background: rgba(35, 70, 56, 0.82);\n      font-size: 0.92rem;\n    }\n\n    .wrong-slide-one-toggle:checked ~ .wrong-carousel-controls .wrong-dot-one,\n    .wrong-slide-two-toggle:checked ~ .wrong-carousel-controls .wrong-dot-two {\n      background: var(--gold);\n      color: var(--ink);\n    }\n\n    .wrong-popup-close {\n      padding: 0 14px;\n      background: rgba(91, 58, 36, 0.86);\n      color: var(--paper);\n    }\n\n    .market-image-story {\n      width: min(100%, 1180px);\n      margin-inline: auto;\n      border: 1px solid rgba(91, 58, 36, 0.18);\n      border-radius: 8px;\n      padding: clamp(18px, 3vw, 30px);\n      background:\n        linear-gradient(145deg, rgba(247, 243, 232, 0.96), rgba(232, 216, 184, 0.68)),\n        radial-gradient(circle at 10% 0%, rgba(185, 146, 69, 0.14), transparent 38%);\n      box-shadow: 0 20px 42px rgba(91, 58, 36, 0.14);\n    }\n\n    .market-image-story::after {\n      content: \"\";\n      display: block;\n      clear: both;\n    }\n\n    .market-theology-visual {\n      float: right;\n      width: min(46%, 520px);\n      margin: 0 0 clamp(16px, 2.4vw, 26px) clamp(20px, 3vw, 38px);\n      border: 1px solid rgba(91, 58, 36, 0.18);\n      border-radius: 8px;\n      overflow: hidden;\n      background: rgba(255, 255, 255, 0.62);\n      box-shadow: 0 18px 34px rgba(91, 58, 36, 0.16);\n    }\n\n    .market-theology-visual img {\n      display: block;\n      width: 100%;\n      height: auto;\n      object-fit: contain;\n    }\n\n    .market-image-story p {\n      margin: 0 0 clamp(12px, 1.8vw, 18px);\n      color: var(--muted);\n      font-size: clamp(1rem, 1.45vw, 1.16rem);\n      line-height: 1.66;\n    }\n\n    .market-image-story p:last-child {\n      margin-bottom: 0;\n    }\n\n    .market-image-story .closing-line {\n      color: var(--forest);\n      font-weight: 750;\n    }\n\n    .scripture-reflection {\n      width: min(100%, 1180px);\n      margin-inline: auto;\n    }\n\n    .value-bars {\n      display: grid;\n      gap: 12px;\n      margin: 18px 0;\n    }\n\n    .value-row {\n      display: grid;\n      grid-template-columns: minmax(98px, 0.32fr) minmax(0, 1fr);\n      gap: 12px;\n      align-items: center;\n      color: var(--deep-kraft);\n      font-size: 0.9rem;\n      font-weight: 750;\n    }\n\n    .value-track {\n      min-height: 22px;\n      overflow: hidden;\n      border: 1px solid rgba(91, 58, 36, 0.16);\n      border-radius: 999px;\n      background: rgba(255, 255, 255, 0.58);\n    }\n\n    .value-fill {\n      display: flex;\n      min-height: 22px;\n      align-items: center;\n      justify-content: flex-end;\n      padding-right: 10px;\n      border-radius: 999px;\n      background: linear-gradient(90deg, var(--leaf), var(--gold));\n      color: var(--paper);\n      font-size: 0.78rem;\n      font-weight: 800;\n    }\n\n    .choice-list {\n      display: grid;\n      gap: 12px;\n      margin-top: 14px;\n    }\n\n    .choice-list .card {\n      display: grid;\n      gap: 6px;\n      box-shadow: none;\n    }\n\n    .ordinary-art-page {\n      min-height: calc(100vh - 120px);\n      display: grid;\n      gap: clamp(24px, 4vw, 42px);\n      align-content: start;\n      border-radius: 8px;\n      background:\n        linear-gradient(180deg, rgba(247, 243, 232, 0.84), rgba(247, 243, 232, 0.94)),\n        radial-gradient(circle at 12% 0%, rgba(217, 154, 61, 0.12), transparent 34%);\n    }\n\n    .ordinary-story {\n      color: #76604f;\n    }\n\n    .ordinary-story::after {\n      content: \"\";\n      display: block;\n      clear: both;\n    }\n\n    .ordinary-hero {\n      float: left;\n      width: min(59%, 740px);\n      margin: 0 clamp(24px, 3vw, 42px) 18px 0;\n      border-radius: 8px;\n      object-fit: contain;\n      box-shadow: 0 18px 34px rgba(91, 58, 36, 0.16);\n    }\n\n    .ordinary-copy {\n      max-width: none;\n    }\n\n    .ordinary-copy p {\n      margin: 0 0 clamp(12px, 1.6vw, 18px);\n      color: #76604f;\n      font-size: clamp(1.08rem, 1.65vw, 1.38rem);\n      line-height: 1.62;\n    }\n\n    .ordinary-copy p:last-child {\n      margin-bottom: 0;\n    }\n\n    .ordinary-copy .ordinary-small {\n      max-width: 72ch;\n      margin-top: clamp(10px, 1.6vw, 18px);\n      padding-top: clamp(10px, 1.4vw, 16px);\n      border-top: 1px solid rgba(118, 96, 79, 0.18);\n      font-size: clamp(0.98rem, 1.35vw, 1.14rem);\n      line-height: 1.58;\n    }\n\n    .transparent-quote-row {\n      display: grid;\n      grid-template-columns: repeat(2, minmax(280px, 1fr));\n      gap: clamp(34px, 8vw, 110px);\n      align-items: end;\n      margin: 0;\n      padding: clamp(12px, 2.2vw, 20px) clamp(8px, 2vw, 18px);\n      border-radius: 8px;\n      background:\n        linear-gradient(90deg, rgba(247, 243, 232, 0.18), rgba(232, 216, 184, 0.32), rgba(247, 243, 232, 0.18));\n    }\n\n    .transparent-quote {\n      margin: 0;\n      border: 0;\n      background: transparent;\n      box-shadow: none;\n      display: grid;\n      place-items: end center;\n    }\n\n    .transparent-quote img {\n      display: block;\n      width: 100%;\n      max-width: 640px;\n      height: clamp(130px, 15vw, 178px);\n      object-fit: contain;\n      mix-blend-mode: multiply;\n      filter: drop-shadow(0 10px 12px rgba(91, 58, 36, 0.12));\n    }\n\n    .economics-step-page {\n      display: grid;\n      gap: clamp(18px, 3vw, 26px);\n      border: 1px solid rgba(91, 58, 36, 0.18);\n      border-radius: 8px;\n      padding: clamp(18px, 3vw, 28px);\n      background:\n        linear-gradient(145deg, rgba(247, 243, 232, 0.96), rgba(232, 216, 184, 0.72)),\n        radial-gradient(circle at 15% 0%, rgba(217, 154, 61, 0.14), transparent 36%);\n      box-shadow: 0 22px 48px rgba(91, 58, 36, 0.16);\n    }\n\n    .economics-step-header {\n      display: flex;\n      gap: 16px;\n      align-items: flex-start;\n      justify-content: space-between;\n    }\n\n    .economics-step-header h2,\n    .economics-step-header p {\n      margin: 0;\n    }\n\n    .economics-step-header h2 {\n      margin-top: 5px;\n      color: var(--forest);\n      font-size: clamp(1.65rem, 4vw, 2.55rem);\n      line-height: 1.08;\n    }\n\n    .completion-icon {\n      flex: 0 0 auto;\n      width: 36px;\n      height: 36px;\n      display: grid;\n      place-items: center;\n      border: 1px solid rgba(185, 146, 69, 0.44);\n      border-radius: 8px;\n      background: rgba(247, 243, 232, 0.72);\n      color: var(--forest);\n      font-weight: 850;\n      box-shadow: 0 10px 20px rgba(91, 58, 36, 0.1);\n    }\n\n    .economics-teaching-panel {\n      border: 1px solid rgba(91, 58, 36, 0.16);\n      border-radius: 8px;\n      padding: clamp(18px, 3vw, 28px);\n      background:\n        linear-gradient(180deg, rgba(247, 243, 232, 0.92), rgba(255, 255, 255, 0.55)),\n        radial-gradient(circle at 85% 8%, rgba(124, 143, 90, 0.1), transparent 34%);\n      box-shadow: 0 18px 38px rgba(91, 58, 36, 0.12);\n    }\n\n    .economics-hero-layout {\n      display: grid;\n      grid-template-columns: minmax(280px, 0.9fr) minmax(380px, 1.1fr);\n      gap: clamp(18px, 3vw, 28px);\n      align-items: stretch;\n      margin-top: clamp(14px, 2vw, 18px);\n    }\n\n    .economics-hero-copy {\n      display: grid;\n      grid-template-rows: minmax(0, 1fr) minmax(0, 1fr);\n      gap: clamp(16px, 2.4vw, 22px);\n      min-width: 0;\n    }\n\n    .economics-hero-copy .teaching-section {\n      display: grid;\n      align-content: center;\n      margin-top: 0;\n    }\n\n    .economics-square-image {\n      display: block;\n      width: 100%;\n      height: 100%;\n      min-height: clamp(520px, 58vw, 650px);\n      margin: 0;\n      border: 1px solid rgba(91, 58, 36, 0.18);\n      border-radius: 8px;\n      object-fit: cover;\n      object-position: center;\n      background: var(--cream);\n      box-shadow: 0 18px 34px rgba(91, 58, 36, 0.18);\n    }\n\n    .teaching-section {\n      margin-top: clamp(16px, 2.5vw, 22px);\n      overflow: hidden;\n      border: 1px solid rgba(91, 58, 36, 0.13);\n      border-left: 4px solid rgba(185, 146, 69, 0.72);\n      border-radius: 8px;\n      padding: clamp(12px, 1.8vw, 16px) clamp(14px, 2vw, 18px);\n      background:\n        linear-gradient(145deg, rgba(255, 255, 255, 0.46), rgba(247, 243, 232, 0.7)),\n        radial-gradient(circle at 100% 0%, rgba(185, 146, 69, 0.1), transparent 34%);\n      box-shadow: 0 12px 26px rgba(91, 58, 36, 0.08);\n    }\n\n    .teaching-section.everyday-life-section {\n      border-left-color: rgba(79, 107, 58, 0.86);\n      background:\n        linear-gradient(145deg, rgba(124, 143, 90, 0.14), rgba(247, 243, 232, 0.76)),\n        radial-gradient(circle at 100% 0%, rgba(79, 107, 58, 0.12), transparent 34%);\n    }\n\n    .teaching-section.misunderstanding-section {\n      border-color: rgba(217, 154, 61, 0.34);\n      border-left-color: var(--amber);\n      background:\n        linear-gradient(145deg, rgba(217, 154, 61, 0.2), rgba(247, 243, 232, 0.78)),\n        radial-gradient(circle at 100% 0%, rgba(154, 107, 63, 0.14), transparent 34%);\n    }\n\n    .teaching-section.misunderstanding-section h3 {\n      color: var(--deep-kraft);\n    }\n\n    .teaching-section.takeaway-section {\n      border-left-color: rgba(35, 70, 56, 0.84);\n      background:\n        linear-gradient(145deg, rgba(35, 70, 56, 0.1), rgba(247, 243, 232, 0.76)),\n        radial-gradient(circle at 100% 0%, rgba(185, 146, 69, 0.12), transparent 34%);\n    }\n\n    .teaching-section:first-of-type {\n      margin-top: 0;\n    }\n\n    .teaching-section h3,\n    .teaching-section p {\n      margin: 0;\n    }\n\n    .teaching-section h3 {\n      margin-bottom: 10px;\n      color: var(--forest);\n      font-size: clamp(1.05rem, 2vw, 1.22rem);\n      line-height: 1.2;\n    }\n\n    .teaching-section p + p {\n      margin-top: 22px;\n    }\n\n    .teaching-section p,\n    .economics-list li {\n      color: var(--deep-kraft);\n      font-size: clamp(0.96rem, 1.55vw, 1.08rem);\n      line-height: 1.72;\n    }\n\n    .economics-list {\n      grid-template-columns: repeat(auto-fit, minmax(210px, 1fr));\n      gap: 8px 18px;\n      margin: 9px 0 0;\n      padding-left: 18px;\n    }\n\n    .economics-visual-card {\n      clear: both;\n      margin: clamp(18px, 3vw, 26px) 0;\n      border: 1px solid rgba(91, 58, 36, 0.16);\n      border-radius: 8px;\n      padding: clamp(10px, 1.8vw, 14px);\n      background:\n        linear-gradient(145deg, rgba(247, 243, 232, 0.86), rgba(255, 255, 255, 0.58)),\n        radial-gradient(circle at 12% 0%, rgba(217, 154, 61, 0.12), transparent 32%);\n      box-shadow: 0 16px 34px rgba(91, 58, 36, 0.12);\n    }\n\n    .economics-visual-card img {\n      display: block;\n      width: 100%;\n      max-height: 520px;\n      object-fit: contain;\n      border-radius: 6px;\n    }\n\n    .quote-card-row,\n    .concept-card-row {\n      display: grid;\n      grid-template-columns: repeat(2, minmax(0, 1fr));\n      gap: clamp(14px, 2.5vw, 20px);\n    }\n\n    .quote-card-row {\n      align-items: stretch;\n    }\n\n    .quote-card {\n      display: grid;\n      place-items: center;\n      border: 1px solid rgba(185, 146, 69, 0.34);\n      border-left: 5px solid var(--gold);\n      border-radius: 8px;\n      padding: 12px;\n      background: rgba(247, 243, 232, 0.74);\n      box-shadow: 0 16px 34px rgba(91, 58, 36, 0.12);\n    }\n\n    .quote-card img {\n      width: 100%;\n      max-height: 210px;\n      object-fit: contain;\n      mix-blend-mode: multiply;\n      filter: drop-shadow(0 10px 12px rgba(91, 58, 36, 0.12));\n    }\n\n    .concept-card-row {\n      grid-template-columns: repeat(3, minmax(0, 1fr));\n    }\n\n    .concept-card {\n      border: 1px solid rgba(91, 58, 36, 0.15);\n      border-radius: 8px;\n      padding: 16px;\n      background: rgba(255, 255, 255, 0.5);\n      box-shadow: 0 14px 28px rgba(91, 58, 36, 0.1);\n    }\n\n    .concept-card strong {\n      display: block;\n      margin-bottom: 7px;\n      color: var(--gold);\n      font-size: 0.76rem;\n      text-transform: uppercase;\n    }\n\n    .concept-card h3,\n    .concept-card p {\n      margin: 0;\n    }\n\n    .concept-card h3 {\n      margin-bottom: 7px;\n      color: var(--forest);\n      font-size: 1.04rem;\n    }\n\n    .concept-card p {\n      color: var(--muted);\n      line-height: 1.5;\n    }\n\n    .economics-highlight {\n      border: 1px solid rgba(185, 146, 69, 0.36);\n      border-left: 5px solid var(--gold);\n      border-radius: 8px;\n      padding: 16px 18px;\n      background: rgba(217, 154, 61, 0.1);\n      box-shadow: 0 14px 28px rgba(91, 58, 36, 0.1);\n    }\n\n    .economics-highlight h3,\n    .economics-highlight p {\n      margin: 0;\n    }\n\n    .economics-highlight h3 {\n      margin-bottom: 7px;\n      color: var(--forest);\n    }\n\n    .economics-choice-chart {\n      display: grid;\n      gap: 12px;\n      border: 1px solid rgba(91, 58, 36, 0.15);\n      border-radius: 8px;\n      padding: 16px;\n      background: rgba(255, 255, 255, 0.48);\n      box-shadow: 0 14px 28px rgba(91, 58, 36, 0.1);\n    }\n\n    .economics-choice-chart h3 {\n      margin: 0;\n      color: var(--forest);\n    }\n\n    .choice-chart-row {\n      display: grid;\n      grid-template-columns: minmax(90px, 0.18fr) minmax(0, 1fr);\n      gap: 12px;\n      align-items: center;\n    }\n\n    .choice-chart-row strong {\n      color: var(--deep-kraft);\n    }\n\n    .choice-chart-tags {\n      display: flex;\n      gap: 8px;\n      flex-wrap: wrap;\n    }\n\n    .choice-chart-tags span {\n      border: 1px solid rgba(79, 107, 58, 0.2);\n      border-radius: 999px;\n      padding: 6px 10px;\n      background: rgba(124, 143, 90, 0.17);\n      color: var(--forest);\n      font-size: 0.86rem;\n      font-weight: 750;\n    }\n\n    .faith-reflection {\n      border-color: rgba(217, 154, 61, 0.44);\n      border-left-color: var(--amber);\n      background:\n        linear-gradient(145deg, rgba(217, 154, 61, 0.13), rgba(247, 243, 232, 0.74));\n    }\n\n    .pillars-page {\n      display: grid;\n      gap: clamp(18px, 3vw, 28px);\n    }\n\n    .pillars-hero {\n      display: grid;\n      gap: 10px;\n      justify-items: center;\n      text-align: center;\n      padding: clamp(18px, 3vw, 28px);\n      border: 1px solid rgba(91, 58, 36, 0.18);\n      border-radius: 8px;\n      background:\n        linear-gradient(145deg, rgba(247, 243, 232, 0.94), rgba(232, 216, 184, 0.7)),\n        radial-gradient(circle at 50% 0%, rgba(217, 154, 61, 0.16), transparent 36%);\n      box-shadow: 0 18px 42px rgba(91, 58, 36, 0.14);\n    }\n\n    .pillars-hero h2 {\n      max-width: 980px;\n      margin: 0;\n      font-family: Georgia, \"Times New Roman\", serif;\n      color: var(--forest);\n      font-size: clamp(2rem, 6vw, 4.4rem);\n      line-height: 1;\n    }\n\n    .pillars-hero p {\n      max-width: 760px;\n      margin: 0;\n      color: var(--deep-kraft);\n      font-size: clamp(0.98rem, 1.5vw, 1.12rem);\n    }\n\n    .pillars-grid {\n      position: relative;\n      display: grid;\n      grid-template-columns: repeat(2, minmax(260px, 1fr));\n      gap: clamp(16px, 2.5vw, 26px);\n      padding: clamp(12px, 2vw, 18px);\n      border-radius: 8px;\n      overflow: visible;\n      background:\n        linear-gradient(180deg, rgba(247, 243, 232, 0.42), rgba(232, 216, 184, 0.36)),\n        radial-gradient(circle at 0% 100%, rgba(185, 146, 69, 0.12), transparent 30%);\n    }\n\n    .pillar-card-shell {\n      position: relative;\n      min-height: clamp(210px, 22vw, 280px);\n      z-index: 0;\n    }\n\n    .pillar-card-shell:has(.pillar-toggle:checked) {\n      z-index: 1000;\n    }\n\n    .pillar-toggle {\n      position: absolute;\n      width: 1px;\n      height: 1px;\n      opacity: 0;\n      pointer-events: none;\n    }\n\n    .pillar-flip-card {\n      position: relative;\n      display: block;\n      width: 100%;\n      height: 100%;\n      min-height: inherit;\n      cursor: pointer;\n      transform-style: preserve-3d;\n      transition:\n        transform 420ms ease,\n        filter 180ms ease;\n    }\n\n    .pillar-toggle:checked + .pillar-flip-card {\n      z-index: 4;\n      transform: translateY(-2px) scale(1.01);\n      filter: drop-shadow(0 24px 30px rgba(91, 58, 36, 0.18));\n    }\n\n    .pillar-toggle:focus-visible + .pillar-flip-card .pillar-face {\n      outline: 3px solid rgba(185, 146, 69, 0.45);\n      outline-offset: 3px;\n    }\n\n    .pillar-face {\n      position: absolute;\n      inset: 0;\n      overflow: hidden;\n      border: 2px solid rgba(185, 146, 69, 0.58);\n      border-radius: 8px;\n      backface-visibility: hidden;\n      box-shadow:\n        0 18px 34px rgba(91, 58, 36, 0.13),\n        inset 0 1px 0 rgba(255, 255, 255, 0.7);\n    }\n\n    .pillar-front {\n      display: grid;\n      grid-template-columns: minmax(112px, 0.42fr) minmax(0, 1fr);\n      gap: clamp(14px, 2vw, 22px);\n      align-items: center;\n      padding: clamp(22px, 3vw, 32px);\n      background:\n        linear-gradient(145deg, rgba(247, 243, 232, 0.96), rgba(232, 216, 184, 0.56)),\n        radial-gradient(circle at 0% 100%, rgba(185, 146, 69, 0.18), transparent 34%);\n    }\n\n    .pillar-icon {\n      display: grid;\n      place-items: center;\n      min-height: 128px;\n      color: var(--gold);\n    }\n\n    .pillar-icon img {\n      display: block;\n      width: min(150px, 100%);\n      height: auto;\n      max-height: 150px;\n      object-fit: contain;\n      filter: drop-shadow(0 10px 10px rgba(91, 58, 36, 0.16));\n    }\n\n    .pillar-front h3,\n    .pillar-front p,\n    .pillar-popup-card h3,\n    .pillar-popup-card p {\n      margin: 0;\n    }\n\n    .pillar-front h3 {\n      color: var(--forest);\n      font-family: Georgia, \"Times New Roman\", serif;\n      font-size: clamp(1.75rem, 3.5vw, 3.15rem);\n      line-height: 1;\n    }\n\n    .pillar-front p {\n      max-width: 30rem;\n      margin-top: 10px;\n      color: var(--deep-kraft);\n      font-size: clamp(0.95rem, 1.35vw, 1.08rem);\n      line-height: 1.35;\n    }\n\n    .pillar-front span {\n      display: inline-flex;\n      width: fit-content;\n      margin-top: 14px;\n      border-radius: 999px;\n      padding: 6px 10px;\n      background: rgba(185, 146, 69, 0.16);\n      color: var(--deep-kraft);\n      font-size: 0.78rem;\n      font-weight: 800;\n      text-transform: uppercase;\n    }\n\n    .pillar-popup {\n      position: fixed;\n      inset: 0;\n      z-index: 9999;\n      isolation: isolate;\n      display: grid;\n      place-items: center;\n      padding: clamp(16px, 4vw, 38px);\n      background: rgba(23, 19, 15, 0.68);\n      backdrop-filter: blur(5px);\n      opacity: 0;\n      pointer-events: none;\n      visibility: hidden;\n      transition:\n        opacity 180ms ease,\n        visibility 180ms ease;\n    }\n\n    .pillar-toggle:checked ~ .pillar-popup {\n      opacity: 1;\n      pointer-events: auto;\n      visibility: visible;\n    }\n\n    .pillar-popup-backdrop {\n      position: absolute;\n      inset: 0;\n      cursor: pointer;\n    }\n\n    .pillar-popup-card {\n      position: relative;\n      z-index: 1;\n      width: min(760px, calc(100vw - 28px));\n      max-height: min(84vh, 680px);\n      display: grid;\n      gap: clamp(14px, 2vw, 18px);\n      overflow: auto;\n      border: 2px solid rgba(185, 146, 69, 0.58);\n      border-radius: 8px;\n      padding: clamp(20px, 3vw, 32px);\n      background:\n        linear-gradient(145deg, #f7f3e8, #f0e5cf),\n        radial-gradient(circle at 100% 0%, rgba(79, 107, 58, 0.12), transparent 36%);\n      box-shadow: 0 34px 90px rgba(23, 19, 15, 0.52);\n      transform: translateY(18px) rotateX(4deg) scale(0.97);\n      transform-origin: center;\n      transition: transform 220ms ease;\n    }\n\n    .pillar-toggle:checked ~ .pillar-popup .pillar-popup-card {\n      transform: translateY(0) rotateX(0) scale(1);\n    }\n\n    .pillar-popup-close {\n      position: sticky;\n      top: 0;\n      justify-self: end;\n      border: 1px solid rgba(91, 58, 36, 0.2);\n      border-radius: 999px;\n      padding: 7px 12px;\n      background: #f7f3e8;\n      color: var(--deep-kraft);\n      cursor: pointer;\n      font-size: 0.78rem;\n      font-weight: 850;\n      text-transform: uppercase;\n      box-shadow: 0 8px 16px rgba(91, 58, 36, 0.12);\n    }\n\n    .pillar-popup-card strong {\n      color: var(--gold);\n      font-size: 0.76rem;\n      text-transform: uppercase;\n    }\n\n    .pillar-popup-card h3 {\n      color: var(--forest);\n      max-width: 100%;\n      font-size: clamp(1.55rem, 3vw, 2.25rem);\n      line-height: 1.16;\n      text-wrap: balance;\n    }\n\n    .pillar-popup-card p {\n      color: var(--muted);\n      max-width: 68ch;\n      font-size: clamp(1.04rem, 1.55vw, 1.18rem);\n      line-height: 1.65;\n    }\n\n    .complete-button {\n      display: inline-flex;\n      min-height: 42px;\n      align-items: center;\n      justify-content: center;\n      margin-top: 22px;\n      padding: 0 16px;\n      border: 1px solid var(--forest);\n      border-radius: 8px;\n      background: linear-gradient(145deg, var(--forest), var(--ubuntu));\n      color: var(--paper);\n      font: inherit;\n      font-weight: 750;\n      cursor: pointer;\n      box-shadow: 0 12px 24px rgba(35, 70, 56, 0.22);\n      transition:\n        background 160ms ease,\n        transform 160ms ease,\n        box-shadow 160ms ease;\n    }\n\n    .complete-button:hover {\n      background: linear-gradient(145deg, #1d3a2f, var(--forest));\n      box-shadow: 0 14px 28px rgba(35, 70, 56, 0.26);\n      transform: translateY(-1px);\n    }\n\n    @media (max-width: 640px) {\n      .comparison {\n        grid-template-columns: 1fr;\n      }\n\n      .comparison div:first-child {\n        border-right: 0;\n        border-bottom: 1px solid rgba(91, 58, 36, 0.18);\n      }\n\n      .value-row {\n        grid-template-columns: 1fr;\n        gap: 6px;\n      }\n\n      .ordinary-hero {\n        float: none;\n        width: 100%;\n        margin: 0 0 18px;\n      }\n\n      .ordinary-copy p {\n        font-size: 1rem;\n        line-height: 1.56;\n      }\n\n      .market-theology-visual {\n        float: none;\n        width: 100%;\n        margin: 0 0 18px;\n      }\n\n      .audio-discussion-button {\n        width: min(100%, 360px);\n      }\n\n      .audio-popup-panel {\n        min-height: min(72vh, 560px);\n        padding: 18px;\n      }\n\n      .soundwave {\n        min-height: 130px;\n      }\n\n      .wrong-thinking-images,\n      .wrong-card-grid {\n        grid-template-columns: 1fr;\n      }\n\n      .wrong-thinking-image img {\n        min-height: 0;\n      }\n\n      .wrong-flip-card {\n        min-height: 0;\n      }\n\n      .market-image-story p {\n        font-size: 1rem;\n        line-height: 1.58;\n      }\n\n      .transparent-quote-row {\n        grid-template-columns: 1fr;\n      }\n\n      .economics-step-header {\n        align-items: flex-start;\n      }\n\n      .economics-hero-layout {\n        grid-template-columns: 1fr;\n      }\n\n      .economics-square-image {\n        height: auto;\n        min-height: 0;\n        object-fit: contain;\n      }\n\n      .quote-card-row,\n      .concept-card-row {\n        grid-template-columns: 1fr;\n      }\n\n      .pillars-grid {\n        grid-template-columns: 1fr;\n      }\n\n      .pillar-card-shell {\n        min-height: 250px;\n      }\n\n      .pillar-front {\n        grid-template-columns: 1fr;\n        justify-items: center;\n        text-align: center;\n      }\n\n      .choice-chart-row {\n        grid-template-columns: 1fr;\n        gap: 7px;\n      }\n    }\n  </style>\n  <main class=\"rich-step\" data-rich-lesson-step>\n    \n      <section class=\"market-theology-page\">\n        <section class=\"audio-discussion\" aria-label=\"Audio discussion\">\n          <p class=\"audio-discussion-copy\">Click the button to listen to the discussion.</p>\n          <input\n            class=\"audio-discussion-toggle\"\n            type=\"checkbox\"\n            id=\"level-1-session-1-the-daily-grind-wallet-worldview-audio\"\n            data-rich-popup-toggle\n            data-audio-toggle\n            data-audio-target=\"#level-1-session-1-the-daily-grind-wallet-worldview-audio-player\"\n          />\n          <label class=\"audio-discussion-button\" for=\"level-1-session-1-the-daily-grind-wallet-worldview-audio\">\n            <img\n              src=\"https://static.wixstatic.com/media/7638b6_4d265beddab44939b223089de3158338~mv2.png\"\n              alt=\"Open audio discussion\"\n            />\n          </label>\n          <div class=\"audio-popup\" role=\"dialog\" aria-label=\"Audio discussion player\">\n            <label class=\"audio-popup-scrim\" for=\"level-1-session-1-the-daily-grind-wallet-worldview-audio\" aria-label=\"Close audio discussion\"></label>\n            <div class=\"audio-popup-panel\">\n              <div class=\"soundwave\" aria-hidden=\"true\">\n                <span></span>\n                <span></span>\n                <span></span>\n                <span></span>\n                <span></span>\n                <span></span>\n                <span></span>\n                <span></span>\n                <span></span>\n                <span></span>\n              </div>\n              <audio id=\"level-1-session-1-the-daily-grind-wallet-worldview-audio-player\" controls preload=\"metadata\">\n                <source src=\"https://static.wixstatic.com/mp3/7638b6_731005efcdc94fc89592073673540bd8.m4a\" type=\"audio/mp4\" />\n              </audio>\n              <label class=\"audio-popup-close\" for=\"level-1-session-1-the-daily-grind-wallet-worldview-audio\">Close</label>\n            </div>\n          </div>\n        </section>\n\n        <section class=\"wrong-thinking-section\" aria-label=\"Wrong thinking about economics\">\n          <h2>Wrong thinking about economics</h2>\n\n          <div class=\"wrong-thinking-images\" aria-label=\"Wrong economic thinking visuals\">\n            <figure class=\"wrong-thinking-image\">\n              <img\n                src=\"https://static.wixstatic.com/media/7638b6_a9ec244496864c2aa33dfb8d0104c46f~mv2.png\"\n                alt=\"Wrong thinking about economics visual\"\n              />\n            </figure>\n            <figure class=\"wrong-thinking-image\">\n              <img\n                src=\"https://static.wixstatic.com/media/7638b6_c05404d411b64c23b78e6c2ce1ab3cff~mv2.png\"\n                alt=\"Wrong thinking about economics comparison visual\"\n              />\n            </figure>\n          </div>\n\n          <p class=\"scholars-heading\">Find out what scholars says</p>\n\n          <div class=\"wrong-card-grid\" aria-label=\"Wrong thinking flip cards\">\n            <article class=\"wrong-flip-card\">\n              <input class=\"wrong-flip-toggle\" type=\"checkbox\" id=\"level-1-session-1-the-daily-grind-wrong-card-one\" data-rich-popup-toggle />\n              <label class=\"wrong-flip-cover\" for=\"level-1-session-1-the-daily-grind-wrong-card-one\">\n                <img\n                  src=\"https://static.wixstatic.com/media/7638b6_d6bf992a5e584631869e2b85fb075a6b~mv2.png\"\n                  alt=\"First wrong thinking flip card cover\"\n                />\n                <span class=\"wrong-flip-cta\">Find out more</span>\n              </label>\n              <div class=\"wrong-carousel-popup\" role=\"dialog\" aria-label=\"First wrong thinking carousel\">\n                <label class=\"wrong-popup-scrim\" for=\"level-1-session-1-the-daily-grind-wrong-card-one\" aria-label=\"Close first carousel\"></label>\n                <div class=\"wrong-popup-panel\">\n                  <div class=\"wrong-carousel\">\n                    <input class=\"wrong-slide-toggle wrong-slide-one-toggle\" type=\"radio\" name=\"level-1-session-1-the-daily-grind-wrong-card-one-carousel\" id=\"level-1-session-1-the-daily-grind-wrong-card-one-slide-one\" checked />\n                    <input class=\"wrong-slide-toggle wrong-slide-two-toggle\" type=\"radio\" name=\"level-1-session-1-the-daily-grind-wrong-card-one-carousel\" id=\"level-1-session-1-the-daily-grind-wrong-card-one-slide-two\" />\n                    <div class=\"wrong-carousel-window\">\n                      <div class=\"wrong-carousel-track\">\n                        <figure class=\"wrong-carousel-slide\">\n                          <img\n                            src=\"https://static.wixstatic.com/media/7638b6_f8c5c53c17a9489895b293cb53e9aad1~mv2.png\"\n                            alt=\"First carousel slide for the first wrong thinking card\"\n                          />\n                        </figure>\n                        <figure class=\"wrong-carousel-slide\">\n                          <img\n                            src=\"https://static.wixstatic.com/media/7638b6_2951a0d17d8a4389b4c29a84397af2a1~mv2.png\"\n                            alt=\"Second carousel slide for the first wrong thinking card\"\n                          />\n                        </figure>\n                      </div>\n                    </div>\n                    <div class=\"wrong-carousel-controls\">\n                      <label class=\"wrong-dot-one\" for=\"level-1-session-1-the-daily-grind-wrong-card-one-slide-one\">1</label>\n                      <label class=\"wrong-dot-two\" for=\"level-1-session-1-the-daily-grind-wrong-card-one-slide-two\">2</label>\n                      <label class=\"wrong-popup-close\" for=\"level-1-session-1-the-daily-grind-wrong-card-one\">Close</label>\n                    </div>\n                  </div>\n                </div>\n              </div>\n            </article>\n\n            <article class=\"wrong-flip-card\">\n              <input class=\"wrong-flip-toggle\" type=\"checkbox\" id=\"level-1-session-1-the-daily-grind-wrong-card-two\" data-rich-popup-toggle />\n              <label class=\"wrong-flip-cover\" for=\"level-1-session-1-the-daily-grind-wrong-card-two\">\n                <img\n                  src=\"https://static.wixstatic.com/media/7638b6_af53a18f98cc4c84ba49e3357ca743f1~mv2.png\"\n                  alt=\"Second wrong thinking flip card cover\"\n                />\n                <span class=\"wrong-flip-cta\">Find out more</span>\n              </label>\n              <div class=\"wrong-carousel-popup\" role=\"dialog\" aria-label=\"Second wrong thinking carousel\">\n                <label class=\"wrong-popup-scrim\" for=\"level-1-session-1-the-daily-grind-wrong-card-two\" aria-label=\"Close second carousel\"></label>\n                <div class=\"wrong-popup-panel\">\n                  <div class=\"wrong-carousel\">\n                    <input class=\"wrong-slide-toggle wrong-slide-one-toggle\" type=\"radio\" name=\"level-1-session-1-the-daily-grind-wrong-card-two-carousel\" id=\"level-1-session-1-the-daily-grind-wrong-card-two-slide-one\" checked />\n                    <input class=\"wrong-slide-toggle wrong-slide-two-toggle\" type=\"radio\" name=\"level-1-session-1-the-daily-grind-wrong-card-two-carousel\" id=\"level-1-session-1-the-daily-grind-wrong-card-two-slide-two\" />\n                    <div class=\"wrong-carousel-window\">\n                      <div class=\"wrong-carousel-track\">\n                        <figure class=\"wrong-carousel-slide\">\n                          <img\n                            src=\"https://static.wixstatic.com/media/7638b6_a894e89316604b2d8d33688b97811959~mv2.png\"\n                            alt=\"First carousel slide for the second wrong thinking card\"\n                          />\n                        </figure>\n                        <figure class=\"wrong-carousel-slide\">\n                          <img\n                            src=\"https://static.wixstatic.com/media/7638b6_16fe653c77904001a72b0786dd8fce2c~mv2.png\"\n                            alt=\"Second carousel slide for the second wrong thinking card\"\n                          />\n                        </figure>\n                      </div>\n                    </div>\n                    <div class=\"wrong-carousel-controls\">\n                      <label class=\"wrong-dot-one\" for=\"level-1-session-1-the-daily-grind-wrong-card-two-slide-one\">1</label>\n                      <label class=\"wrong-dot-two\" for=\"level-1-session-1-the-daily-grind-wrong-card-two-slide-two\">2</label>\n                      <label class=\"wrong-popup-close\" for=\"level-1-session-1-the-daily-grind-wrong-card-two\">Close</label>\n                    </div>\n                  </div>\n                </div>\n              </div>\n            </article>\n          </div>\n        </section>\n\n        <article class=\"market-image-story\">\n          <figure class=\"market-theology-visual\">\n            <img\n              src=\"https://static.wixstatic.com/media/7638b6_5f69750a6fca42718c433eaf03285fc7~mv2.png\"\n              alt=\"Faithonomics visual exploring economic thinking and theological teaching\"\n            />\n          </figure>\n          <p>\n            At times our Christian way of thinking sees economics as being a science based on natural laws, and we\n            should only correct it when it is in clear conflict with Bible morals. For example, liberal economic\n            theories suggest that society works because people focus on their own needs and try to outdo each other.\n          </p>\n          <p>\n            On the other hand, in socialist theories, the key goals are people cooperating and ensuring everyone is\n            treated equally. However, both of these approaches omit God from these important human interactions.\n          </p>\n          <p>\n            Economic thought and theological teaching in the past were deeply connected. God''s provision and justice\n            formed the foundation for understanding how society should organise resources and care for people.\n          </p>\n          <p>\n            During the period of the Enlightenment, God''s wisdom was replaced by reason and human experience. Divine\n            guidance on economic thought was replaced by thinkers like Adam Smith with the autonomous market system\n            and Karl Marx with the socio-economic \"laws\" of historical development.\n          </p>\n          <p class=\"closing-line\">\n            Removing God from the choices we make in what we have, how we work and how we use what we have directly\n            affects our relationship with God. Redefining God, humanity and our worship of God.\n          </p>\n        </article>\n\n        <section class=\"callout scripture-reflection\">\n          <h3>Read Matthew 6:25-34</h3>\n          <p>\n            Read Matthew 6:25-34, and reflect on what the portion of Scripture says about how we should make\n            our economic choices. How do I practically apply it to my daily life, my work/business, or who I\n            vote for?\n          </p>\n          <textarea aria-label=\"Matthew 6 economic choice reflection\" rows=\"7\" placeholder=\"Write your reflection here...\"></textarea>\n        </section>\n      </section>\n    \n    <button class=\"complete-button\" data-classroom-complete data-score=\"5\" data-max-score=\"5\">Complete step</button>\n  </main>\n"}]}'::jsonb, 'course-faithonomics-core', 'level-1', null, null, null, null, null, null, null, null, 1),
  ('lessons', 'level-1-session-2-competing-paradigms', '{"id":"level-1-session-2-competing-paradigms","courseId":"course-faithonomics-core","moduleId":"level-1","title":"Session 2: Competing Paradigms","summary":"Develop the core Faithonomics principle of \"Competing Paradigms\" and connect it to everyday economic decisions.","sequence":2,"required":true,"estimatedMinutes":50,"imageUrl":"https://static.wixstatic.com/media/7638b6_ee2d807107c24a2db2c5787e73578b85~mv2.png","imageAlt":"Split papercraft road showing a grey decline path and green-gold renewal path through an open door.","content":[{"id":"level-1-session-2-competing-paradigms-session-teaching","kind":"text","title":"Step 1: Core Teaching","body":"Level 1: Economic Alignment frames Competing Paradigms as part of faithful economic discipleship. Learners identify the dominant assumption, compare it with God''s economy, and name the decision that needs alignment."},{"id":"level-1-session-2-competing-paradigms-session-scripture","kind":"scripture","title":"Step 2: Scripture and Principle","body":"Read the assigned passage, identify the economic principle, and state how it challenges scarcity, ownership, status, work, generosity, or integrity."},{"id":"level-1-session-2-competing-paradigms-session-application","kind":"text","title":"Step 3: Business Application","body":"Apply the principle to a business case: stakeholders, value creation, pricing, wages, stewardship, customer care, supplier relationships, and long-term trust."},{"id":"level-1-session-2-competing-paradigms-resource-link","kind":"webLink","title":"Step 4: Wix Resource Link","body":"Open the lecturer-approved web resource stored in Wix CMS, then return here to confirm you reviewed it.","url":"https://www.wix.com/learn"},{"id":"level-1-session-2-competing-paradigms-session-reflection","kind":"customHtml","title":"Step 5: Reflection Checkpoint","body":"<main><h2>Competing Paradigms</h2><p>Choose one action you will practise before the next session.</p><button data-classroom-complete data-score=\"5\" data-max-score=\"5\">Mark reflection complete</button></main>"}]}'::jsonb, 'course-faithonomics-core', 'level-1', null, null, null, null, null, null, null, null, 2),
  ('lessons', 'level-1-session-3-strategic-alignment', '{"id":"level-1-session-3-strategic-alignment","courseId":"course-faithonomics-core","moduleId":"level-1","title":"Session 3: Strategic Alignment","summary":"Develop the core Faithonomics principle of \"Strategic Alignment\" and connect it to everyday economic decisions.","sequence":3,"required":true,"estimatedMinutes":50,"imageUrl":"https://static.wixstatic.com/media/7638b6_fb2b739765044e78b2dcbd33e7a43038~mv2.png","imageAlt":"Papercraft strategy map with compass, cross marker, route, growth chart and scales.","content":[{"id":"level-1-session-3-strategic-alignment-session-teaching","kind":"text","title":"Step 1: Core Teaching","body":"Level 1: Economic Alignment frames Strategic Alignment as part of faithful economic discipleship. Learners identify the dominant assumption, compare it with God''s economy, and name the decision that needs alignment."},{"id":"level-1-session-3-strategic-alignment-session-scripture","kind":"scripture","title":"Step 2: Scripture and Principle","body":"Read the assigned passage, identify the economic principle, and state how it challenges scarcity, ownership, status, work, generosity, or integrity."},{"id":"level-1-session-3-strategic-alignment-session-application","kind":"text","title":"Step 3: Business Application","body":"Apply the principle to a business case: stakeholders, value creation, pricing, wages, stewardship, customer care, supplier relationships, and long-term trust."},{"id":"level-1-session-3-strategic-alignment-teaching-video","kind":"video","title":"Step 4: Teaching Video","body":"Watch the teaching video before attempting the strategic alignment checkpoint.","url":"wix-media://video/faithonomics-strategic-alignment.mp4"},{"id":"level-1-session-3-strategic-alignment-session-reflection","kind":"customHtml","title":"Step 5: Reflection Checkpoint","body":"<main><h2>Strategic Alignment</h2><p>Choose one action you will practise before the next session.</p><button data-classroom-complete data-score=\"5\" data-max-score=\"5\">Mark reflection complete</button></main>"}]}'::jsonb, 'course-faithonomics-core', 'level-1', null, null, null, null, null, null, null, null, 3),
