  ('enrolments', 'enrol-faithonomics-amina', '{"id":"enrol-faithonomics-amina","courseId":"course-faithonomics-core","memberId":"member-learner-001","contactId":"contact-learner-001","source":"admin","status":"active","enrolledAt":"2026-06-01T08:00:00.000Z"}'::jsonb, 'course-faithonomics-core', null, null, null, null, 'member-learner-001', null, null, null, 'active', null),
  ('submissions', 'submission-paradigms-amina', '{"id":"submission-paradigms-amina","activityId":"activity-economic-alignment-reflection","lessonId":"level-1-session-2-competing-paradigms","courseId":"course-faithonomics-core","enrolmentId":"enrol-faithonomics-amina","memberId":"member-learner-001","contactId":"contact-learner-001","responseText":"I often inherit a scarcity mindset at work. God''s economy reframes my role as stewardship, so I need to make decisions that build trust and room for others.","status":"submitted","submittedAt":"2026-06-21T12:30:00.000Z"}'::jsonb, 'course-faithonomics-core', null, 'level-1-session-2-competing-paradigms', 'activity-economic-alignment-reflection', null, 'member-learner-001', 'enrol-faithonomics-amina', null, null, 'submitted', null),
  ('discussionPosts', 'post-kingdom-first-001', '{"id":"post-kingdom-first-001","activityId":"activity-kingdom-first-discussion","memberId":"member-learner-002","authorName":"Thabo Mokoena","body":"Matthew 6 challenges how I think about overtime. I often say yes because I fear falling behind, even when it damages family life and rest. Seeking the kingdom first would mean planning honestly, working faithfully, but not treating income as my saviour.","createdAt":"2026-06-22T07:45:00.000Z"}'::jsonb, null, null, null, 'activity-kingdom-first-discussion', null, 'member-learner-002', null, null, null, null, null),
  ('discussionPosts', 'post-kingdom-first-002', '{"id":"post-kingdom-first-002","activityId":"activity-kingdom-first-discussion","memberId":"member-learner-003","authorName":"Lerato Dlamini","body":"For me this affects voting and business policy. I usually ask which option protects my own costs first. This passage asks me to consider righteousness too: who is protected, who is ignored, and whether the policy helps people live with dignity.","createdAt":"2026-06-22T08:05:00.000Z"}'::jsonb, null, null, null, 'activity-kingdom-first-discussion', null, 'member-learner-003', null, null, null, null, null),
  ('discussionPosts', 'post-four-pillars-001', '{"id":"post-four-pillars-001","activityId":"activity-four-pillars-discussion","memberId":"member-learner-002","authorName":"Thabo Mokoena","body":"I chose property. For me, property is not only a house or money. It is also my phone, my time, and the tools I use for work. This pillar challenges me to ask whether I use what I have only for myself, or whether I can steward it in a way that helps others.","createdAt":"2026-06-22T08:10:00.000Z"}'::jsonb, null, null, null, 'activity-four-pillars-discussion', null, 'member-learner-002', null, null, null, null, null),
  ('discussionPosts', 'post-four-pillars-002', '{"id":"post-four-pillars-002","activityId":"activity-four-pillars-discussion","memberId":"member-learner-003","authorName":"Lerato Dlamini","body":"Relationships stood out to me. Buying, selling, borrowing, and working are never only private choices. They can build trust or damage trust. I think a business can lose money in the long run if it treats relationships as less important than quick profit.","createdAt":"2026-06-22T08:18:00.000Z"}'::jsonb, null, null, null, 'activity-four-pillars-discussion', null, 'member-learner-003', null, null, null, null, null),
  ('discussionPosts', 'post-four-pillars-003', '{"id":"post-four-pillars-003","activityId":"activity-four-pillars-discussion","memberId":"member-learner-004","authorName":"Johan van der Merwe","body":"I chose consumption. Every purchase trains my habits. Sometimes I buy because I need something, but sometimes I buy because I feel pressure to look successful. This pillar helps me think about whether my choices serve a good purpose.","createdAt":"2026-06-22T08:26:00.000Z"}'::jsonb, null, null, null, 'activity-four-pillars-discussion', null, 'member-learner-004', null, null, null, null, null),
  ('discussionPosts', 'post-monday-practice-001', '{"id":"post-monday-practice-001","activityId":"activity-monday-discussion","memberId":"member-learner-002","authorName":"Thabo Mokoena","body":"My Monday action is to review our supplier terms through the lens of fairness, not only speed.","createdAt":"2026-06-22T08:15:00.000Z"}'::jsonb, null, null, null, 'activity-monday-discussion', null, 'member-learner-002', null, null, null, null, null),
  ('discussionReplies', 'reply-kingdom-first-001', '{"id":"reply-kingdom-first-001","postId":"post-kingdom-first-001","memberId":"member-lecturer-001","authorName":"Faithonomics Lecturer","body":"Strong connection between anxiety and work. What boundary could show trust in God without becoming irresponsible toward your employer or family?","createdAt":"2026-06-22T08:30:00.000Z"}'::jsonb, null, null, null, null, null, 'member-lecturer-001', null, 'post-kingdom-first-001', null, null, null),
  ('discussionReplies', 'reply-kingdom-first-002', '{"id":"reply-kingdom-first-002","postId":"post-kingdom-first-002","memberId":"member-learner-004","authorName":"Johan van der Merwe","body":"Your point about voting helps me. Could you add one practical question you would ask before supporting a policy?","createdAt":"2026-06-22T08:42:00.000Z"}'::jsonb, null, null, null, null, null, 'member-learner-004', null, 'post-kingdom-first-002', null, null, null),
  ('discussionReplies', 'reply-monday-practice-001', '{"id":"reply-monday-practice-001","postId":"post-monday-practice-001","memberId":"member-lecturer-001","authorName":"Faithonomics Lecturer","body":"Good start. Add one measurable sign that the supplier relationship has become more just.","createdAt":"2026-06-22T09:00:00.000Z"}'::jsonb, null, null, null, null, null, 'member-lecturer-001', null, 'post-monday-practice-001', null, null, null)
